import React, { useState, useRef, useCallback } from 'react';
import { generateImage } from '../services/geminiService';
import { UploadIcon, SparklesIcon, ResetIcon, DownloadIcon, CompareIcon, ExpandIcon, CloseIcon } from './icons';
import { EditMode, FurnitureOptionId, Style } from '../types';
import 'image-comparison-slider';

// Fix for custom element 'image-comparison-slider' not being recognized by TypeScript JSX.
const ImageComparisonSlider = 'image-comparison-slider' as any;

interface ImageEditorProps {
  onImageDoubleClick: (url: string) => void;
  selectedStyle: Style | null;
  geometryValue: number;
  selectedFurnitureOption: FurnitureOptionId;
  furniturePrompt: string;
  editMode: EditMode;
  isMoodboard: boolean;
  contrastValue: number;
  onSetContrastValue: (value: number) => void;
}

export const ImageEditor: React.FC<ImageEditorProps> = ({
  onImageDoubleClick,
  selectedStyle,
  geometryValue,
  selectedFurnitureOption,
  furniturePrompt,
  editMode,
  isMoodboard,
  contrastValue,
  onSetContrastValue,
}) => {
  const [originalImage, setOriginalImage] = useState<File | null>(null);
  const [originalImageUrl, setOriginalImageUrl] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isComparing, setIsComparing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleImageReset = () => {
    setOriginalImage(null);
    setOriginalImageUrl(null);
    setGeneratedImageUrl(null);
    setError(null);
    setIsComparing(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  }

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      handleImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleGenerate = useCallback(async () => {
    if (!originalImage) return;

    setIsLoading(true);
    setError(null);
    setGeneratedImageUrl(null);
    setIsComparing(false);

    let finalPrompt = '';
    if (editMode === 'prompt') {
      finalPrompt = prompt;
    } else if (selectedStyle) {
      finalPrompt = `${furniturePrompt}in a ${selectedStyle.name} style, ${selectedStyle.prompt}`;
    } else {
        setError('Please select a style or switch to prompt mode.');
        setIsLoading(false);
        return;
    }

    try {
      const base64String = await generateImage(originalImage, finalPrompt, geometryValue, contrastValue);
      setGeneratedImageUrl(`data:image/png;base64,${base64String}`);
    } catch (e: any) {
      console.error(e);
      setError(`An error occurred during image generation: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  }, [originalImage, editMode, prompt, selectedStyle, furniturePrompt, geometryValue, contrastValue]);

  const handleDownload = () => {
    if (!generatedImageUrl) return;
    const link = document.createElement('a');
    link.href = generatedImageUrl;
    link.download = `render-master-ai-${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const renderImageContainer = (isOutput: boolean) => {
    const imageUrl = isOutput ? generatedImageUrl : originalImageUrl;
    const title = isOutput ? "Generated Image" : "Original Image";

    if (isLoading && isOutput) {
        return (
            <div className="w-full h-full flex flex-col items-center justify-center bg-gray-100 rounded-lg shimmer-bg">
                <p className="mt-4 text-gray-800 font-bold text-lg z-10">Generating your vision...</p>
                <p className="text-gray-600 mt-1 z-10">This may take a moment.</p>
            </div>
        )
    }

    if (!imageUrl) {
        return (
            <div className={`w-full h-full flex items-center justify-center rounded-lg ${!isOutput ? 'bg-white border-2 border-dashed border-gray-300' : 'bg-gray-100'}`}>
                <div className="text-center text-gray-500 p-4">
                    {isOutput ? 'Your generated image will appear here.' : 'Upload an image to get started.'}
                </div>
            </div>
        )
    }

    return (
        <img
            src={imageUrl}
            alt={title}
            className="w-full h-full object-contain"
            onDoubleClick={() => onImageDoubleClick(imageUrl)}
        />
    )
  }

  const comparisonSlider = (
    <ImageComparisonSlider className="slider-with-custom-handle">
        <img slot="first" src={originalImageUrl!} alt="Original" />
        <img slot="second" src={generatedImageUrl!} alt="Generated" />
        <div slot="handle" className="custom-handle">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24" fill="currentColor"><path d="M12 4l-1.41 1.41L16.17 11H4v2h12.17l-5.58 5.59L12 20l8-8z"/><path d="M12 20l-1.41-1.41L5.83 13H20v-2H5.83l5.58-5.59L12 4l-8 8z"/></svg>
        </div>
    </ImageComparisonSlider>
  );

  return (
    <main className="flex-1 p-4 md:p-6 flex flex-col bg-gray-50 overflow-auto">
      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6 min-h-0">
        {/* Left Column: Image Upload & Original */}
        <div
          className="relative w-full h-full flex items-center justify-center rounded-lg group"
          onDragOver={(e) => e.preventDefault()}
          onDrop={handleDrop}
        >
          {!originalImageUrl ? (
             <div className="text-center p-6 cursor-pointer border-2 border-dashed border-gray-400 rounded-xl hover:bg-gray-100 transition-colors w-full h-full flex flex-col justify-center items-center" onClick={() => fileInputRef.current?.click()}>
                <UploadIcon className="w-12 h-12 text-gray-400 mx-auto mb-4 breathing-icon" />
                <h3 className="text-lg font-semibold text-gray-700">Drop your image here</h3>
                <p className="text-gray-500">or click to browse</p>
              </div>
          ) : (
            <>
              <div className="absolute top-0 left-0 bg-black/50 text-white text-xs font-bold px-2 py-1 rounded-br-lg z-10">BEFORE</div>
              {renderImageContainer(false)}
              <button onClick={handleImageReset} className="absolute top-2 right-2 bg-black/50 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity" title="Clear Image">
                <CloseIcon className="w-5 h-5" />
              </button>
            </>
          )}
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
        </div>

        {/* Right Column: Generated Image */}
        <div className="relative w-full h-full rounded-lg overflow-hidden">
          {isComparing && originalImageUrl && generatedImageUrl ? comparisonSlider : renderImageContainer(true)}
        </div>
      </div>

      {error && <div className="text-center text-red-500 font-semibold mt-4">{error}</div>}

      {/* Bottom controls */}
      <div className="shrink-0 pt-4 mt-4 border-t border-gray-200">
        <div className="mb-4">
          <label className="text-sm font-semibold text-gray-700 mb-2 block">Contrast</label>
          <input
            type="range"
            min="-50"
            max="50"
            value={contrastValue}
            onChange={(e) => onSetContrastValue(parseInt(e.target.value, 10))}
            className="w-full contrast-slider"
            style={{ '--progress': `${((contrastValue + 50) / 100) * 100}%` } as React.CSSProperties}
            disabled={isLoading}
          />
        </div>
        <div className="flex flex-col md:flex-row items-center gap-4">
          <div className="w-full flex-1">
            <input
              type="text"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder={editMode === 'prompt' ? "Describe your vision..." : "Style selected. Use the sidebar or switch to Prompt mode."}
              disabled={isLoading || editMode !== 'prompt'}
              className="w-full px-4 py-3 text-gray-800 bg-white rounded-lg border border-gray-300 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-colors"
            />
          </div>
          <div className="w-full md:w-auto flex items-center gap-2">
            <button
              onClick={handleGenerate}
              disabled={!originalImage || isLoading || isMoodboard}
              className="flex-1 flex items-center justify-center px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg shadow-md hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 text-base"
            >
              <SparklesIcon className={`w-5 h-5 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
              {isLoading ? 'Generating...' : `Generate`}
            </button>
             <button onClick={handleImageReset} title="Reset" className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors" disabled={isLoading}><ResetIcon className="w-5 h-5"/></button>
             <button onClick={() => setIsComparing(!isComparing)} title="Compare" disabled={!originalImageUrl || !generatedImageUrl} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><CompareIcon className="w-5 h-5"/></button>
             <button onClick={handleDownload} title="Download" disabled={!generatedImageUrl} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><DownloadIcon className="w-5 h-5"/></button>
             <button onClick={() => generatedImageUrl && onImageDoubleClick(generatedImageUrl)} title="Expand" disabled={!generatedImageUrl} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><ExpandIcon className="w-5 h-5"/></button>
          </div>
        </div>
      </div>
    </main>
  );
};

import React, { useState, useRef } from 'react';
import { generateMoodboard } from '../services/geminiService';
import { UploadIcon, SparklesIcon, ResetIcon, DownloadIcon, CloseIcon } from './icons';

const MAX_IMAGES = 6;

interface MoodboardCreatorProps {
  onImageDoubleClick: (url: string) => void;
}

export const MoodboardCreator: React.FC<MoodboardCreatorProps> = ({ onImageDoubleClick }) => {
  const [sourceImages, setSourceImages] = useState<File[]>([]);
  const [sourceImageUrls, setSourceImageUrls] = useState<string[]>([]);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = (Array.from(e.target.files || []) as File[]).slice(0, MAX_IMAGES - sourceImages.length);
    if (files.length > 0) {
      setSourceImages(prev => [...prev, ...files]);
      const newUrls = files.map(file => URL.createObjectURL(file));
      setSourceImageUrls(prev => [...prev, ...newUrls]);
    }
  };

  const removeImage = (index: number) => {
    URL.revokeObjectURL(sourceImageUrls[index]);
    setSourceImages(prev => prev.filter((_, i) => i !== index));
    setSourceImageUrls(prev => prev.filter((_, i) => i !== index));
  };

  const handleGenerate = async () => {
    if (sourceImages.length === 0) return;

    setIsLoading(true);
    setError(null);
    try {
      const base64String = await generateMoodboard(sourceImages);
      setGeneratedImageUrl(`data:image/png;base64,${base64String}`);
    } catch (e: any) {
      setError(`An error occurred: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  const handleReset = () => {
    sourceImageUrls.forEach(url => URL.revokeObjectURL(url));
    setSourceImages([]);
    setSourceImageUrls([]);
    setGeneratedImageUrl(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleDownload = () => {
    if (!generatedImageUrl) return;
    const link = document.createElement('a');
    link.href = generatedImageUrl;
    link.download = 'moodboard.png';
    link.click();
  };

  return (
    <main className="flex-1 p-6 flex flex-col items-center justify-center bg-white overflow-auto">
        <div className="text-center mb-6">
            <h1 className="text-3xl font-bold text-gray-900">Moodboard Generator</h1>
            <p className="text-lg text-gray-600 mt-1">Upload 1 to 6 images to create a visual theme.</p>
        </div>
        <div className="w-full max-w-6xl flex-1 md:grid md:grid-cols-2 md:gap-8 space-y-6 md:space-y-0">
            {/* Left side */}
            <div className="flex flex-col h-full">
                <div className="grid grid-cols-3 gap-4 mb-4">
                    {sourceImageUrls.map((url, index) => (
                        <div key={index} className="relative aspect-square">
                            <img src={url} alt={`source ${index + 1}`} className="w-full h-full object-cover rounded-lg"/>
                            <button onClick={() => removeImage(index)} className="absolute top-1 right-1 bg-black/50 text-white p-1 rounded-full hover:bg-black/80">
                                <CloseIcon className="w-4 h-4" />
                            </button>
                        </div>
                    ))}
                    {sourceImages.length < MAX_IMAGES && (
                        <div 
                            className="flex items-center justify-center aspect-square border-2 border-dashed border-gray-300 rounded-lg cursor-pointer hover:bg-gray-100"
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <div className="text-center text-gray-500">
                                <UploadIcon className="w-8 h-8 mx-auto"/>
                                <span className="text-xs mt-1 block">Add Image</span>
                            </div>
                        </div>
                    )}
                </div>
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={handleFileChange} 
                    multiple 
                    accept="image/*" 
                    className="hidden"
                    disabled={sourceImages.length >= MAX_IMAGES}
                />

                <div className="flex items-center gap-4 mt-auto">
                    <button
                        onClick={handleGenerate}
                        disabled={sourceImages.length === 0 || isLoading}
                        className="flex-1 flex items-center justify-center px-6 py-4 bg-indigo-600 text-white font-semibold rounded-lg shadow-md hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 text-lg"
                    >
                        <SparklesIcon className={`w-6 h-6 mr-3 ${isLoading ? 'animate-spin' : ''}`} />
                         {isLoading ? 'Generating...' : `Generate`}
                    </button>
                    <button onClick={handleReset} className="p-4 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors" title="Reset">
                        <ResetIcon className="w-6 h-6" />
                    </button>
                </div>
            </div>

            {/* Right side */}
            <div className="flex flex-col items-center justify-center border-2 border-dashed border-gray-300 rounded-lg bg-white relative h-full min-h-[300px] md:min-h-0">
                {isLoading ? (
                    <div className="text-center text-gray-500">
                        <SparklesIcon className="w-12 h-12 mx-auto mb-4 animate-spin"/>
                        <p>Generating moodboard...</p>
                    </div>
                ) : generatedImageUrl ? (
                    <>
                        <img onDoubleClick={() => onImageDoubleClick(generatedImageUrl)} src={generatedImageUrl} alt="Generated Moodboard" className="max-w-full max-h-full object-contain rounded-lg p-2 cursor-pointer" />
                        <button onClick={handleDownload} className="absolute top-4 right-4 bg-black/50 p-2 rounded-full text-white hover:bg-black/70 transition-colors" title="Download Image">
                            <DownloadIcon className="w-5 h-5" />
                        </button>
                    </>
                ) : (
                    <p className="text-gray-400">Your generated moodboard will appear here.</p>
                )}
            </div>
        </div>
        {error && <p className="text-red-600 text-sm mt-4 text-center">{error}</p>}
    </main>
  );
};

import React, { useState, useMemo } from 'react';
import { Header } from './components/Header';
import { Sidebar } from './components/Sidebar';
import { ImageEditor } from './components/ImageEditor';
import { HomeScreen } from './components/HomeScreen';
import { ImageViewerModal } from './components/ComparisonSliderModal';
import { MoodboardCreator } from './components/MoodboardCreator';
import { Category, Style, FurnitureOptionId, EditMode, ExteriorStyleSubCategory, UserProfile } from './types';
import { FURNITURE_OPTIONS } from './constants';

function App() {
  const [activeProfile, setActiveProfile] = useState<UserProfile | null>(null);

  // Main editor state
  const [activeCategory, setActiveCategory] = useState<Category['id']>('Interiors');
  const [selectedStyle, setSelectedStyle] = useState<Style | null>(null);
  const [geometryValue, setGeometryValue] = useState(50);
  const [selectedFurnitureOption, setSelectedFurnitureOption] = useState<FurnitureOptionId>('change');
  const [editMode, setEditMode] = useState<EditMode>('conceptual');
  const [exteriorStyleSubCategory, setExteriorStyleSubCategory] = useState<ExteriorStyleSubCategory>('preset');
  const [contrastValue, setContrastValue] = useState(0);

  // Style Reference Image state
  const [styleReferenceImage, setStyleReferenceImage] = useState<File | null>(null);
  const [styleReferenceImageUrl, setStyleReferenceImageUrl] = useState<string | null>(null);

  // Modal state
  const [isImageViewerOpen, setIsImageViewerOpen] = useState(false);
  const [viewerImageUrl, setViewerImageUrl] = useState<string | null>(null);

  const handleStyleReferenceImageChange = (file: File | null) => {
    if (styleReferenceImageUrl) {
        URL.revokeObjectURL(styleReferenceImageUrl);
    }
    if (file) {
        setStyleReferenceImage(file);
        setStyleReferenceImageUrl(URL.createObjectURL(file));
    } else {
        setStyleReferenceImage(null);
        setStyleReferenceImageUrl(null);
    }
  };

  const resetEditorState = () => {
    setActiveCategory('Interiors');
    setSelectedStyle(null);
    setGeometryValue(50);
    setSelectedFurnitureOption('change');
    setEditMode('conceptual');
    setExteriorStyleSubCategory('preset');
    setContrastValue(0);
    handleStyleReferenceImageChange(null);
  };

  const handleProfileSelect = (profile: UserProfile) => {
    setActiveProfile(profile);
    resetEditorState();
  };

  const handleGoHome = () => {
    setActiveProfile(null);
    resetEditorState();
  }

  const handleImageDoubleClick = (url: string) => {
    setViewerImageUrl(url);
    setIsImageViewerOpen(true);
  };

  const furniturePrompt = useMemo(() => {
    return FURNITURE_OPTIONS.find(opt => opt.id === selectedFurnitureOption)?.prompt || '';
  }, [selectedFurnitureOption]);

  const handleCategoryClick = (id: Category['id']) => {
    setActiveCategory(id);
    setSelectedStyle(null);
    setEditMode('conceptual');
  };

  const handleApplyStyle = (style: Style) => {
    setSelectedStyle(style);
    if (editMode === 'prompt') {
      setEditMode('styles');
    }
  };

  if (!activeProfile) {
    return <HomeScreen onProfileSelect={handleProfileSelect} />;
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-white font-sans antialiased">
      <Header onGoHome={handleGoHome} activeProfile={activeProfile} />

      <div className="flex flex-col md:flex-row flex-1 min-h-0">
          <Sidebar
            activeCategory={activeCategory}
            onCategoryClick={handleCategoryClick}
            selectedStyleId={selectedStyle?.id || null}
            onApplyStyle={handleApplyStyle}
            geometryValue={geometryValue}
            onSetGeometryValue={setGeometryValue}
            selectedFurnitureOption={selectedFurnitureOption}
            onSetFurnitureOption={setSelectedFurnitureOption}
            editMode={editMode}
            onSetEditMode={setEditMode}
            exteriorStyleSubCategory={exteriorStyleSubCategory}
            onSetExteriorStyleSubCategory={setExteriorStyleSubCategory}
            styleReferenceImageUrl={styleReferenceImageUrl}
            onStyleReferenceImageChange={handleStyleReferenceImageChange}
          />

          {activeCategory === 'Moodboard' ? (
            <MoodboardCreator 
              onImageDoubleClick={handleImageDoubleClick}
            />
          ) : (
            <ImageEditor
              onImageDoubleClick={handleImageDoubleClick}
              selectedStyle={selectedStyle}
              geometryValue={geometryValue}
              selectedFurnitureOption={selectedFurnitureOption}
              furniturePrompt={furniturePrompt}
              editMode={editMode}
              isMoodboard={false}
              contrastValue={contrastValue}
              onSetContrastValue={setContrastValue}
              styleReferenceImage={styleReferenceImage}
            />
          )}
      </div>

      <ImageViewerModal
        isOpen={isImageViewerOpen}
        onClose={() => setIsImageViewerOpen(false)}
        imageUrl={viewerImageUrl}
      />
    </div>
  );
}

export default App;

import React, { useRef } from 'react';
import { CATEGORIES, FURNITURE_OPTIONS, CONCEPTUAL_STYLES, ART_STYLES, EXTERIOR_RENDER_STYLES } from '../constants';
import { Category, Style, FurnitureOptionId, EditMode, ExteriorStyleSubCategory } from '../types';
import { CnjImages } from './CnjImages';
import { GeometrySlider } from './GeometrySlider';
import { UploadIcon, CloseIcon } from './icons';

interface SidebarProps {
  activeCategory: Category['id'];
  onCategoryClick: (id: Category['id']) => void;
  selectedStyleId: Style['id'] | null;
  onApplyStyle: (style: Style) => void;
  geometryValue: number;
  onSetGeometryValue: (value: number) => void;
  selectedFurnitureOption: FurnitureOptionId;
  onSetFurnitureOption: (option: FurnitureOptionId) => void;
  editMode: EditMode;
  onSetEditMode: (mode: EditMode) => void;
  exteriorStyleSubCategory: ExteriorStyleSubCategory;
  onSetExteriorStyleSubCategory: (category: ExteriorStyleSubCategory) => void;
  styleReferenceImageUrl: string | null;
  onStyleReferenceImageChange: (file: File | null) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  activeCategory, 
  onCategoryClick,
  selectedStyleId, 
  onApplyStyle,
  geometryValue,
  onSetGeometryValue,
  selectedFurnitureOption,
  onSetFurnitureOption,
  editMode,
  onSetEditMode,
  exteriorStyleSubCategory,
  onSetExteriorStyleSubCategory,
  styleReferenceImageUrl,
  onStyleReferenceImageChange,
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const exteriorConceptualStyles = CONCEPTUAL_STYLES.filter(style => style.id !== 'conceptual-night');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
        onStyleReferenceImageChange(e.target.files[0]);
    }
  };

  return (
    <aside className="w-full md:w-96 bg-gray-100 p-6 flex flex-col space-y-8 overflow-y-auto shrink-0 border-r border-gray-200 no-scrollbar">
      <div>
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Scene</h2>
        <div className="flex items-center bg-white rounded-lg p-1 border border-gray-200">
          {CATEGORIES.map(({ id, Icon }) => (
            <button
              key={id}
              onClick={() => onCategoryClick(id)}
              className={`w-full flex items-center justify-center gap-2 p-2 rounded-md text-sm font-medium transition-colors ${
                activeCategory === id ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
              }`}
            >
              <Icon className="w-5 h-5" />
              {id}
            </button>
          ))}
        </div>
      </div>

      {activeCategory !== 'Moodboard' ? (
        <>
          <GeometrySlider value={geometryValue} onChange={onSetGeometryValue} />

          {activeCategory === 'Interiors' ? (
            <>
              <div>
                <h2 className="text-lg font-semibold text-gray-900 mb-4">Furniture</h2>
                <div className="space-y-2">
                  {FURNITURE_OPTIONS.map((option) => (
                    <button
                      key={option.id}
                      onClick={() => onSetFurnitureOption(option.id)}
                      className={`w-full text-left flex items-center gap-3 p-3 rounded-lg transition-colors border ${
                        selectedFurnitureOption === option.id
                          ? 'bg-indigo-100 border-indigo-300 ring-1 ring-indigo-300'
                          : 'bg-white hover:bg-gray-200/60 border-gray-200'
                      }`}
                    >
                      <option.Icon className={`w-5 h-5 flex-shrink-0 ${selectedFurnitureOption === option.id ? 'text-indigo-600' : 'text-indigo-400'}`} />
                      <span className={`text-sm ${selectedFurnitureOption === option.id ? 'font-semibold text-gray-800' : 'text-gray-700'}`}>{option.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex items-center bg-white rounded-lg p-1 border border-gray-200 mb-4">
                  <button
                    onClick={() => onSetEditMode('conceptual')}
