              )}
            </div>
          )}

          {(editMode === 'prompt') && (
             <div className="p-4 bg-white rounded-lg border border-gray-200">
             <h3 className="text-sm font-semibold text-gray-900 mb-2">Style Reference</h3>
             <p className="text-xs text-gray-500 mb-3">
                Upload an image to use its style (colors, lighting, texture) for the generation.
             </p>

             {!styleReferenceImageUrl ? (
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="border-2 border-dashed border-gray-300 rounded-lg p-6 flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition-colors"
                >
                    <UploadIcon className="w-8 h-8 text-gray-400 mb-2" />
                    <span className="text-xs text-gray-500 font-medium">Click to upload</span>
                </div>
             ) : (
                <div className="relative rounded-lg overflow-hidden border border-gray-200 group">
                    <img src={styleReferenceImageUrl} alt="Style Reference" className="w-full h-32 object-cover" />
                    <button 
                        onClick={() => {
                            onStyleReferenceImageChange(null);
                            if (fileInputRef.current) fileInputRef.current.value = '';
                        }}
                        className="absolute top-1 right-1 bg-black/50 hover:bg-black/70 text-white p-1 rounded-full transition-colors opacity-0 group-hover:opacity-100"
                        title="Remove style reference"
