// Fix for custom element 'image-comparison-slider' not being recognized by TypeScript JSX.
const ImageComparisonSlider = 'image-comparison-slider' as any;

interface ImageEditorProps {
  activeCategory: Category['id'];
  onImageDoubleClick: (url: string) => void;
  selectedStyle: Style | null;
  geometryValue: number;
  selectedFurnitureOption: FurnitureOptionId;
  furniturePrompt: string;
  buildingState: BuildingState;
  editMode: EditMode;
  isMoodboard: boolean;
  contrastValue: number;
  onSetContrastValue: (value: number) => void;
  styleReferenceImage: File | null;
  // External props for AI Render mode
  externalResultUrl?: string | null;
  externalBaseUrl?: string | null;
  externalLoading?: boolean;
  externalError?: string | null;
}

export const ImageEditor: React.FC<ImageEditorProps> = ({
  activeCategory,
  onImageDoubleClick,
  selectedStyle,
  geometryValue,
  selectedFurnitureOption,
  furniturePrompt,
  buildingState,
  editMode,
  isMoodboard,
  contrastValue,
  onSetContrastValue,
  styleReferenceImage,
  externalResultUrl,
  externalBaseUrl,
  externalLoading,
  externalError,
}) => {
  const [originalImage, setOriginalImage] = useState<File | null>(null);
  const [originalImageUrl, setOriginalImageUrl] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isComparing, setIsComparing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Synchronize with external state (e.g., from AI Render mode)
  useEffect(() => {
    if (externalResultUrl) {
        setGeneratedImageUrl(externalResultUrl);
    }
  }, [externalResultUrl]);

  useEffect(() => {
    if (externalBaseUrl) {
        setOriginalImageUrl(externalBaseUrl);
    }
  }, [externalBaseUrl]);

  useEffect(() => {
    if (externalLoading !== undefined) {
        setIsLoading(externalLoading);
    }
  }, [externalLoading]);

  useEffect(() => {
    if (externalError !== undefined) {
        setError(externalError);
    }
  }, [externalError]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleImageReset = () => {
    setOriginalImage(null);
    setOriginalImageUrl(null);
    setGeneratedImageUrl(null);
    setError(null);
    setIsComparing(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  }

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      handleImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleGenerate = useCallback(async () => {
    if (!originalImage) return;

    setIsLoading(true);
    setError(null);
    setGeneratedImageUrl(null);
    setIsComparing(false);

    let finalPrompt = '';
    if (editMode === 'prompt') {
      if (!prompt && !styleReferenceImage) {
          setError('Please enter a prompt or upload a style reference image.');
          setIsLoading(false);
          return;
      }
      finalPrompt = prompt;
    } else if (selectedStyle) {
      // Prompt logic for building state
      let buildingInstruction = '';
      if (buildingState === 'raw') {
        buildingInstruction = "The input image shows a raw construction state (unfinished concrete/brick shell, no paint, no tiles, no cladding, empty/unfinished pools). COMPLETELY FINISH the building: apply high-quality paints, cladding, flooring, and tiles to all surfaces. If a pool structure is present, tile it and fill it with water. Install windows/doors if missing, and landscape the surroundings. Transform this raw shell into a fully finished property ";
      }

      finalPrompt = `${buildingInstruction}${furniturePrompt}in a ${selectedStyle.name} style, ${selectedStyle.prompt}`;
    } else {
        setError('Please select a style or switch to prompt mode.');
        setIsLoading(false);
        return;
    }

    try {
      const base64String = await generateImage(originalImage, finalPrompt, geometryValue, contrastValue, styleReferenceImage);
      setGeneratedImageUrl(`data:image/png;base64,${base64String}`);
    } catch (e: any) {
      console.error(e);
      setError(`An error occurred during image generation: ${e.message}`);
    } finally {
      setIsLoading(false);
    }
  }, [originalImage, editMode, prompt, selectedStyle, furniturePrompt, geometryValue, contrastValue, styleReferenceImage, buildingState]);

  const handleDownload = () => {
    const url = generatedImageUrl || externalResultUrl;
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    link.download = `render-master-ai-${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const renderImageContainer = (isOutput: boolean) => {
    const imageUrl = isOutput ? (generatedImageUrl || externalResultUrl) : (originalImageUrl || externalBaseUrl);
    const title = isOutput ? "Generated Image" : "Original Image";

    if (isLoading && isOutput) {
        return (
            <div className="w-full h-full flex flex-col items-center justify-center bg-gray-100 rounded-lg shimmer-bg">
                <p className="mt-4 text-gray-800 font-bold text-lg z-10">Generating your vision...</p>
                <p className="text-gray-600 mt-1 z-10">This may take a moment.</p>
            </div>
        )
    }

    if (!imageUrl) {
        return (
            <div className={`w-full h-full flex items-center justify-center rounded-lg ${!isOutput ? 'bg-white border-2 border-dashed border-gray-300' : 'bg-gray-100'}`}>
                <div className="text-center text-gray-500 p-4">
                    {isOutput ? 'Your generated image will appear here.' : 'Upload an image to get started.'}
                </div>
            </div>
        )
    }

    return (
        <img
            src={imageUrl}
            alt={title}
            className="w-full h-full object-contain"
            onDoubleClick={() => onImageDoubleClick(imageUrl)}
        />
    )
  }

  const comparisonSlider = (
    <ImageComparisonSlider className="slider-with-custom-handle">
        <img slot="first" src={(originalImageUrl || externalBaseUrl)!} alt="Original" />
        <img slot="second" src={(generatedImageUrl || externalResultUrl)!} alt="Generated" />
        <div slot="handle" className="custom-handle">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24" fill="currentColor"><path d="M12 4l-1.41 1.41L16.17 11H4v2h12.17l-5.58 5.59L12 20l8-8z"/><path d="M12 20l-1.41-1.41L5.83 13H20v-2H5.83l5.58-5.59L12 4l-8 8z"/></svg>
        </div>
    </ImageComparisonSlider>
  );

  const isAIRenderMode = activeCategory === 'AI Render';
  const showSplitControls = !isAIRenderMode; 

  return (
    <main className="flex-1 p-4 md:p-6 flex flex-col bg-gray-50 overflow-auto">
      <div className={`flex-1 ${isAIRenderMode ? 'flex' : 'grid grid-cols-1 md:grid-cols-2'} gap-4 md:gap-6 min-h-0`}>
        {/* Left Column: Image Upload & Original (Hidden in AI Render mode) */}
        {!isAIRenderMode && (
          <div
            className="relative w-full h-full flex items-center justify-center rounded-lg group"
            onDragOver={(e) => e.preventDefault()}
            onDrop={handleDrop}
          >
            {!(originalImageUrl || externalBaseUrl) ? (
               <div className="text-center p-6 cursor-pointer border-2 border-dashed border-gray-400 rounded-xl hover:bg-gray-100 transition-colors w-full h-full flex flex-col justify-center items-center" onClick={() => fileInputRef.current?.click()}>
                  <UploadIcon className="w-12 h-12 text-gray-400 mx-auto mb-4 breathing-icon" />
                  <h3 className="text-lg font-semibold text-gray-700">Drop your image here</h3>
                  <p className="text-gray-500">or click to browse</p>
                </div>
            ) : (
              <>
                <div className="absolute top-0 left-0 bg-black/50 text-white text-xs font-bold px-2 py-1 rounded-br-lg z-10">BEFORE</div>
                {renderImageContainer(false)}
                {!externalBaseUrl && (
                  <button onClick={handleImageReset} className="absolute top-2 right-2 bg-black/50 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity" title="Clear Image">
                      <CloseIcon className="w-5 h-5" />
                  </button>
                )}
              </>
            )}
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
          </div>
        )}

        {/* Output Area (Generated Image) */}
        <div className="relative w-full h-full rounded-lg overflow-hidden flex-1">
            {externalResultUrl && <div className="absolute top-0 left-0 bg-indigo-600 text-white text-xs font-bold px-2 py-1 rounded-br-lg z-10 uppercase">AI Render Result</div>}
            {isComparing && (originalImageUrl || externalBaseUrl) && (generatedImageUrl || externalResultUrl) ? comparisonSlider : renderImageContainer(true)}
        </div>
      </div>

      {error && <div className="text-center text-red-500 font-semibold mt-4">{error}</div>}

      {/* Bottom controls - only show if not in external control mode like AI Render */}
      {showSplitControls && (
        <div className="shrink-0 pt-4 mt-4 border-t border-gray-200">
            <div className="mb-4">
            <label className="text-sm font-semibold text-gray-700 mb-2 block">Contrast</label>
            <input
                type="range"
                min="-50"
                max="50"
                value={contrastValue}
                onChange={(e) => onSetContrastValue(parseInt(e.target.value, 10))}
                className="w-full contrast-slider"
                style={{ '--progress': `${((contrastValue + 50) / 100) * 100}%` } as React.CSSProperties}
                disabled={isLoading}
            />
            </div>
            <div className="flex flex-col md:flex-row items-center gap-4">
            <div className="w-full flex-1">
                <input
                type="text"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder={editMode === 'prompt' ? "Describe your vision (optional if style image provided)..." : "Style selected. Use the sidebar or switch to Prompt mode."}
                disabled={isLoading || editMode !== 'prompt'}
                className="w-full px-4 py-3 text-gray-800 bg-white rounded-lg border border-gray-300 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-colors"
                />
            </div>
            <div className="w-full md:w-auto flex items-center gap-2">
                <button
                onClick={handleGenerate}
                disabled={!originalImage || isLoading || isMoodboard}
                className="flex-1 flex items-center justify-center px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg shadow-md hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 text-base"
                >
                <SparklesIcon className={`w-5 h-5 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
                {isLoading ? 'Generating...' : `Generate`}
                </button>
                <button onClick={handleImageReset} title="Reset" className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors" disabled={isLoading}><ResetIcon className="w-5 h-5"/></button>
                <button onClick={() => setIsComparing(!isComparing)} title="Compare" disabled={!(originalImageUrl || externalBaseUrl) || !(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><CompareIcon className="w-5 h-5"/></button>
                <button onClick={handleDownload} title="Download" disabled={!(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><DownloadIcon className="w-5 h-5"/></button>
                <button onClick={() => (generatedImageUrl || externalResultUrl) && onImageDoubleClick((generatedImageUrl || externalResultUrl)!)} title="Expand" disabled={!(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><ExpandIcon className="w-5 h-5"/></button>
            </div>
            </div>
        </div>
      )}

      {isAIRenderMode && (generatedImageUrl || externalResultUrl) && (
        <div className="shrink-0 pt-4 mt-4 flex justify-center gap-4">
             <button onClick={() => setIsComparing(!isComparing)} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <CompareIcon className="w-5 h-5" />
                Compare Before/After
             </button>
             <button onClick={handleDownload} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <DownloadIcon className="w-5 h-5" />
                Download Render
             </button>
             <button onClick={() => onImageDoubleClick((generatedImageUrl || externalResultUrl)!)} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <ExpandIcon className="w-5 h-5" />
                Full Screen
             </button>
        </div>
      )}
    </main>
  );
};

import React from 'react';

export type SubscriptionPlan = 'free' | 'pro' | 'enterprise';

export interface User {
  id: string;
  email: string;
  name: string;
  plan: SubscriptionPlan;
  credits: number;
}

export interface Category {
  id: 'Interiors' | 'Exteriors' | 'Moodboard' | 'AI Render' | 'Floorplan';
  Icon: React.FC<React.SVGProps<SVGSVGElement>>;
  isPro?: boolean;
}

export interface Style {
  id: string;
  name: string;
  image: string;
  prompt: string;
}

export type EditMode = 'conceptual' | 'styles' | 'prompt';

export type ExteriorStyleSubCategory = 'preset' | 'conceptual';

export type FurnitureOptionId = 'keep' | 'change' | 'empty';

export type BuildingState = 'raw' | 'ready';

export type AIRenderMode = 'keep-texture' | 'creative';

export interface FurnitureOption {
  id: FurnitureOptionId;
  label: string;
  prompt: string;
  Icon: React.FC<React.SVGProps<SVGSVGElement>>;
}

export type UserProfile = 'user' | 'arkitecna';

import React, { useState, useMemo, useEffect } from 'react';
import { Header } from './components/Header';
import { Sidebar } from './components/Sidebar';
import { ImageEditor } from './components/ImageEditor';
import { HomeScreen } from './components/HomeScreen';
import { ImageViewerModal } from './components/ComparisonSliderModal';
import { MoodboardCreator } from './components/MoodboardCreator';
import PaymentPage from './components/PaymentPage';
import { Category, Style, FurnitureOptionId, EditMode, ExteriorStyleSubCategory, User, SubscriptionPlan, AIRenderMode, UserProfile, BuildingState } from './types';
import { FURNITURE_OPTIONS, CATEGORIES } from './constants';
import { generateImage } from './services/geminiService';

function App() {
  // Auth & Subscription State
  const [user, setUser] = useState<User | null>(null);
  const [showPayment, setShowPayment] = useState(false);

  // Main editor state
  const [activeCategory, setActiveCategory] = useState<Category['id']>('Interiors');
  const [selectedStyle, setSelectedStyle] = useState<Style | null>(null);
  const [geometryValue, setGeometryValue] = useState(50);
  const [selectedFurnitureOption, setSelectedFurnitureOption] = useState<FurnitureOptionId>('change');
  const [buildingState, setBuildingState] = useState<BuildingState>('ready');
  const [editMode, setEditMode] = useState<EditMode>('conceptual');
  const [exteriorStyleSubCategory, setExteriorStyleSubCategory] = useState<ExteriorStyleSubCategory>('preset');
  const [contrastValue, setContrastValue] = useState(0);

  // Style Reference Image state
  const [styleReferenceImage, setStyleReferenceImage] = useState<File | null>(null);
  const [styleReferenceImageUrl, setStyleReferenceImageUrl] = useState<string | null>(null);

  // AI Render State
  const [aiRenderBaseImage, setAiRenderBaseImage] = useState<File | null>(null);
  const [aiRenderBaseImageUrl, setAiRenderBaseImageUrl] = useState<string | null>(null);
  const [aiRenderMode, setAiRenderMode] = useState<AIRenderMode>('creative');
  const [aiRenderCreativity, setAiRenderCreativity] = useState(5);
  const [aiRenderResultUrl, setAiRenderResultUrl] = useState<string | null>(null);
  const [isAiRenderLoading, setIsAiRenderLoading] = useState(false);
  const [aiRenderError, setAiRenderError] = useState<string | null>(null);

  // Floorplan State
  const [floorplanBaseImage, setFloorplanBaseImage] = useState<File | null>(null);
  const [floorplanBaseImageUrl, setFloorplanBaseImageUrl] = useState<string | null>(null);
  const [floorplanResultUrl, setFloorplanResultUrl] = useState<string | null>(null);
  const [isFloorplanLoading, setIsFloorplanLoading] = useState(false);
  const [floorplanError, setFloorplanError] = useState<string | null>(null);

  // Modal state
  const [isImageViewerOpen, setIsImageViewerOpen] = useState(false);
  const [viewerImageUrl, setViewerImageUrl] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const savedUser = localStorage.getItem('rm_user');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('rm_user', JSON.stringify(userData));
  };

  const handleProfileSelect = (profile: UserProfile) => {
    // Simulate direct login based on profile selection
    const isPro = profile === 'arkitecna';
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email: isPro ? 'studio@arkitecna.com' : 'guest@example.com',
      name: isPro ? 'Arkitecna Studio' : 'Guest User',
      plan: isPro ? 'pro' : 'free',
      credits: isPro ? 1000 : 5,
    };
    handleLogin(newUser);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('rm_user');
    resetEditorState();
  };

  const handleUpgrade = (plan: SubscriptionPlan) => {
    if (user) {
      const updatedUser = { ...user, plan };
      setUser(updatedUser);
      localStorage.setItem('rm_user', JSON.stringify(updatedUser));
      setShowPayment(false);
    }
  };

  const handleCategoryClick = (id: Category['id']) => {
    const category = CATEGORIES.find(c => c.id === id);
    if (category?.isPro && (!user || user.plan === 'free')) {
      setShowPayment(true);
      return;
    }
    setActiveCategory(id);
    setSelectedStyle(null);
    setEditMode('conceptual');
    setBuildingState('ready'); // Reset building state on category change
  };

  const handleStyleReferenceImageChange = (file: File | null) => {
    if (styleReferenceImageUrl) URL.revokeObjectURL(styleReferenceImageUrl);
    if (file) {
      setStyleReferenceImage(file);
      setStyleReferenceImageUrl(URL.createObjectURL(file));
    } else {
      setStyleReferenceImage(null);
      setStyleReferenceImageUrl(null);
    }
  };

  const handleAiRenderBaseImageChange = (file: File | null) => {
    if (aiRenderBaseImageUrl) URL.revokeObjectURL(aiRenderBaseImageUrl);
    if (file) {
      setAiRenderBaseImage(file);
      setAiRenderBaseImageUrl(URL.createObjectURL(file));
    } else {
      setAiRenderBaseImage(null);
      setAiRenderBaseImageUrl(null);
    }
    setAiRenderResultUrl(null);
    setAiRenderError(null);
  };

  const handleFloorplanBaseImageChange = (file: File | null) => {
    if (floorplanBaseImageUrl) URL.revokeObjectURL(floorplanBaseImageUrl);
    if (file) {
      setFloorplanBaseImage(file);
      setFloorplanBaseImageUrl(URL.createObjectURL(file));
    } else {
      setFloorplanBaseImage(null);
      setFloorplanBaseImageUrl(null);
    }
    setFloorplanResultUrl(null);
    setFloorplanError(null);
  };

  const resetEditorState = () => {
    setActiveCategory('Interiors');
    setSelectedStyle(null);
    setGeometryValue(50);
    setSelectedFurnitureOption('change');
    setBuildingState('ready');
    setEditMode('conceptual');
    setExteriorStyleSubCategory('preset');
    setContrastValue(0);
    handleStyleReferenceImageChange(null);
    handleAiRenderBaseImageChange(null);
    handleFloorplanBaseImageChange(null);
    setShowPayment(false);
  };

  const handleAIRenderGenerate = async () => {
    if (!aiRenderBaseImage || !user) return;

    if (user.plan === 'free' && user.credits <= 0) {
      setShowPayment(true);
      return;
    }

    setIsAiRenderLoading(true);
    setAiRenderError(null);

    let prompt = aiRenderMode === 'keep-texture' 
      ? "Professionally render this architectural image, keeping the existing textures..."
      : "Creatively render this architectural image...";

    const geometryValue = (10 - aiRenderCreativity) * 10;

    try {
        const base64 = await generateImage(aiRenderBaseImage, prompt, geometryValue, 0);
        setAiRenderResultUrl(`data:image/png;base64,${base64}`);

        // Use credit
        if (user.plan === 'free') {
          const updatedUser = { ...user, credits: user.credits - 1 };
          setUser(updatedUser);
          localStorage.setItem('rm_user', JSON.stringify(updatedUser));
        }
    } catch (e: any) {
        setAiRenderError(e.message || "Failed to generate render.");
    } finally {
        setIsAiRenderLoading(false);
    }
  };

  const handleFloorplanGenerate = async () => {
    if (!floorplanBaseImage || !user || !selectedStyle) return;

    if (user.plan === 'free' && user.credits <= 0) {
      setShowPayment(true);
      return;
    }

    setIsFloorplanLoading(true);
    setFloorplanError(null);

    try {
      // Use existing generateImage function but with floorplan specific prompt and geometry value
      const base64 = await generateImage(floorplanBaseImage, selectedStyle.prompt, geometryValue, 0);
      setFloorplanResultUrl(`data:image/png;base64,${base64}`);

      // Use credit
      if (user.plan === 'free') {
        const updatedUser = { ...user, credits: user.credits - 1 };
        setUser(updatedUser);
        localStorage.setItem('rm_user', JSON.stringify(updatedUser));
      }
    } catch (e: any) {
      setFloorplanError(e.message || "Failed to generate floorplan.");
    } finally {
      setIsFloorplanLoading(false);
    }
  };

  if (!user) {
    return <HomeScreen onProfileSelect={handleProfileSelect} />;
  }

  if (showPayment) {
    return <PaymentPage onSelectPlan={handleUpgrade} onBack={() => setShowPayment(false)} />;
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-white font-sans antialiased">
      <Header onGoHome={resetEditorState} user={user} onLogout={handleLogout} />

      <div className="flex flex-col md:flex-row flex-1 min-h-0">
          <Sidebar
            activeCategory={activeCategory}
            onCategoryClick={handleCategoryClick}
            selectedStyleId={selectedStyle?.id || null}
            onApplyStyle={(s) => setSelectedStyle(s)}
            geometryValue={geometryValue}
            onSetGeometryValue={setGeometryValue}
            selectedFurnitureOption={selectedFurnitureOption}
            onSetFurnitureOption={setSelectedFurnitureOption}
            buildingState={buildingState}
            onSetBuildingState={setBuildingState}
            editMode={editMode}
            onSetEditMode={setEditMode}
            exteriorStyleSubCategory={exteriorStyleSubCategory}
            onSetExteriorStyleSubCategory={setExteriorStyleSubCategory}
            styleReferenceImageUrl={styleReferenceImageUrl}
            onStyleReferenceImageChange={handleStyleReferenceImageChange}
            aiRenderBaseImageUrl={aiRenderBaseImageUrl}
            onAiRenderBaseImageChange={handleAiRenderBaseImageChange}
            aiRenderMode={aiRenderMode}
            onSetAiRenderMode={setAiRenderMode}
            aiRenderCreativity={aiRenderCreativity}
            onSetAiRenderCreativity={setAiRenderCreativity}
            onAIRenderGenerate={handleAIRenderGenerate}
            isAiRenderLoading={isAiRenderLoading}
            user={user}
            // Floorplan props
            floorplanBaseImageUrl={floorplanBaseImageUrl}
            onFloorplanBaseImageChange={handleFloorplanBaseImageChange}
            onFloorplanGenerate={handleFloorplanGenerate}
            isFloorplanLoading={isFloorplanLoading}
          />

          {activeCategory === 'Moodboard' ? (
            <MoodboardCreator 
              onImageDoubleClick={(url) => { setViewerImageUrl(url); setIsImageViewerOpen(true); }}
            />
          ) : (
            <ImageEditor
              activeCategory={activeCategory}
              onImageDoubleClick={(url) => { setViewerImageUrl(url); setIsImageViewerOpen(true); }}
              selectedStyle={selectedStyle}
              geometryValue={geometryValue}
              selectedFurnitureOption={selectedFurnitureOption}
              buildingState={buildingState}
              furniturePrompt={FURNITURE_OPTIONS.find(o => o.id === selectedFurnitureOption)?.prompt || ''}
              editMode={editMode}
              isMoodboard={false}
              contrastValue={contrastValue}
              onSetContrastValue={setContrastValue}
              styleReferenceImage={styleReferenceImage}
              externalResultUrl={
                activeCategory === 'AI Render' ? aiRenderResultUrl :
                activeCategory === 'Floorplan' ? floorplanResultUrl : null
              }
              externalBaseUrl={
                activeCategory === 'AI Render' ? aiRenderBaseImageUrl :
                activeCategory === 'Floorplan' ? floorplanBaseImageUrl : null
              }
              externalLoading={
                activeCategory === 'AI Render' ? isAiRenderLoading :
                activeCategory === 'Floorplan' ? isFloorplanLoading : false
              }
              externalError={
                activeCategory === 'AI Render' ? aiRenderError :
                activeCategory === 'Floorplan' ? floorplanError : null
              }
            />
          )}
      </div>

      <ImageViewerModal
        isOpen={isImageViewerOpen}
        onClose={() => setIsImageViewerOpen(false)}
        imageUrl={viewerImageUrl}
      />
    </div>
  );
}

