                  <button onClick={handleImageReset} className="absolute top-2 right-2 bg-black/50 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity" title="Clear Image">
                      <CloseIcon className="w-5 h-5" />
                  </button>
                )}
              </>
            )}
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
          </div>
        )}

