        <div className="relative w-full h-full rounded-lg overflow-hidden flex-1">
            {externalResultUrl && <div className="absolute top-0 left-0 bg-indigo-600 text-white text-xs font-bold px-2 py-1 rounded-br-lg z-10 uppercase">AI Render Result</div>}
            {isComparing && (originalImageUrl || externalBaseUrl) && (generatedImageUrl || externalResultUrl) ? comparisonSlider : renderImageContainer(true)}
        </div>
      </div>

      {error && <div className="text-center text-red-500 font-semibold mt-4">{error}</div>}

      {/* Bottom controls - only show if not in external control mode like AI Render */}
      {showSplitControls && (
        <div className="shrink-0 pt-4 mt-4 border-t border-gray-200">
            <div className="mb-4">
            <label className="text-sm font-semibold text-gray-700 mb-2 block">Contrast</label>
            <input
                type="range"
                min="-50"
                max="50"
                value={contrastValue}
                onChange={(e) => onSetContrastValue(parseInt(e.target.value, 10))}
                className="w-full contrast-slider"
                style={{ '--progress': `${((contrastValue + 50) / 100) * 100}%` } as React.CSSProperties}
                disabled={isLoading}
            />
            </div>
            <div className="flex flex-col md:flex-row items-center gap-4">
            <div className="w-full flex-1">
                <input
                type="text"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder={getPlaceholderText()}
                disabled={isLoading || editMode !== 'prompt'}
                className="w-full px-4 py-3 text-gray-800 bg-white rounded-lg border border-gray-300 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-colors"
                />
            </div>
            <div className="w-full md:w-auto flex items-center gap-2">
                <button
                onClick={handleGenerate}
                disabled={!originalImage || isLoading || isMoodboard}
                className="flex-1 flex items-center justify-center px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg shadow-md hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 text-base"
                >
                <SparklesIcon className={`w-5 h-5 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
                {isLoading ? 'Generating...' : `Generate`}
                </button>
                <button onClick={handleImageReset} title="Reset" className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors" disabled={isLoading}><ResetIcon className="w-5 h-5"/></button>
                <button onClick={() => setIsComparing(!isComparing)} title="Compare" disabled={!(originalImageUrl || externalBaseUrl) || !(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><CompareIcon className="w-5 h-5"/></button>
                <button onClick={handleDownload} title="Download" disabled={!(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><DownloadIcon className="w-5 h-5"/></button>
                <button onClick={() => (generatedImageUrl || externalResultUrl) && onImageDoubleClick((generatedImageUrl || externalResultUrl)!)} title="Expand" disabled={!(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><ExpandIcon className="w-5 h-5"/></button>
            </div>
            </div>
        </div>
      )}

      {isAIRenderMode && (generatedImageUrl || externalResultUrl) && (
        <div className="shrink-0 pt-4 mt-4 flex justify-center gap-4">
             <button onClick={() => setIsComparing(!isComparing)} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <CompareIcon className="w-5 h-5" />
                Compare Before/After
             </button>
             <button onClick={handleDownload} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <DownloadIcon className="w-5 h-5" />
                Download Render
             </button>
             <button onClick={() => onImageDoubleClick((generatedImageUrl || externalResultUrl)!)} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <ExpandIcon className="w-5 h-5" />
                Full Screen
             </button>
        </div>
      )}
    </main>
  );
};

import { GoogleGenAI, Modality } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

// Helper to convert File to base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      resolve(result.split(',')[1]);
    };
    reader.onerror = (error) => reject(error);
  });
};

const getMimeType = (file: File): string => {
  return file.type;
};

export const generateImage = async (
  originalImage: File,
  prompt: string,
  geometryValue: number,
  contrastValue: number,
  styleReferenceImage: File | null = null
): Promise<string> => {
  const model = 'gemini-2.5-flash-image';

  const imageBase64 = await fileToBase64(originalImage);
  const mimeType = getMimeType(originalImage);

  const parts: any[] = [
    {
      inlineData: {
        data: imageBase64,
        mimeType,
      },
    },
  ];

  const geometryPrompt = `Image geometry preservation level is ${geometryValue} out of 100 (0 is most creative, 100 is most precise).`;
  const contrastPrompt = `Adjust image contrast by ${contrastValue} (-50 is lowest, 50 is highest).`;

  // Base prompt construction
  let fullPrompt = `${prompt}\n\n${geometryPrompt}\n${contrastPrompt}`;

  if (styleReferenceImage) {
      const styleBase64 = await fileToBase64(styleReferenceImage);
      const styleMimeType = getMimeType(styleReferenceImage);
      parts.push({
          inlineData: {
              data: styleBase64,
              mimeType: styleMimeType,
          }
      });

      // If prompt is short/simple, add helper text. If it's a long explicit prompt (like Moodboard), trust the prompt.
      if (prompt.length < 100) {
        fullPrompt = `Using the second image as a style reference (copy colors, materials, and lighting), ${fullPrompt}`;
      }
  }

  const textPart = { text: fullPrompt };
  parts.push(textPart);

  const response = await ai.models.generateContent({
    model,
    contents: { parts },
    config: {
      responseModalities: [Modality.IMAGE],
    },
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return part.inlineData.data;
    }
  }

  throw new Error('No image was generated.');
};

export const generateMoodboard = async (images: File[]): Promise<string> => {
    const model = 'gemini-2.5-flash-image';

    const imageParts = await Promise.all(
        images.map(async (file) => ({
            inlineData: {
                data: await fileToBase64(file),
                mimeType: getMimeType(file),
            },
        }))
    );

    const textPart = { text: `Create a realistic, professional interior design material moodboard composed mainly of square or rectangular swatches of materials and textures.
Arrange all swatches by color palette or tonal harmony — grouped from light to dark, or warm to cool tones — ensuring a cohesive and elegant layout.
Include only authentic material samples such as wood, stone, marble, metal, tile, fabric, and paint.
You may include a maximum of three furniture items (chairs, tables, lamps, or decor pieces) only if they complement the palette — they must be isolated, with no background, cleanly cut out, and perfectly integrated into the layout.
The composition should remain material-focused, with furniture serving only as visual accents.
Use a white or light neutral background, soft natural shadows, and true-to-life lighting to simulate a photographed physical board.
Avoid clutter — no text, logos, hands, props, or environmental backgrounds.
The final result should appear as a professional architect or interior designer’s presentation moodboard — minimalist, curated, tactile, and ready for client presentation.` };

    const parts = [...imageParts, textPart];

    const response = await ai.models.generateContent({
        model,
        contents: { parts },
        config: {
            responseModalities: [Modality.IMAGE],
        },
    });

    for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
            return part.inlineData.data;
        }
    }

    throw new Error('No moodboard image was generated.');
};

export const generateFloorplan = async (
  originalImage: File,
  style: '2d' | '3d'
): Promise<string> => {
  const model = 'gemini-2.5-flash-image';
  const imageBase64 = await fileToBase64(originalImage);
  const mimeType = getMimeType(originalImage);

  const imagePart = {
    inlineData: {
      data: imageBase64,
      mimeType,
    },
  };

  const prompt2d = "Clean and vectorize this hand-drawn floor plan into a clear architectural line drawing. Keep proportions identical, convert all hand lines into precise black CAD-style lines on white background. Lines shall be perfectly straight , correct small line's imperfection to have clean, straight line.No textures, no shadows, only geometry lines.";

  if (style === '2d') {
    const response = await ai.models.generateContent({
        model,
        contents: { parts: [imagePart, { text: prompt2d }] },
        config: { responseModalities: [Modality.IMAGE] },
    });
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) return part.inlineData.data;
    }
    throw new Error('2D floorplan generation failed.');
  }

  // 3D Style - Step 1: Clean 2D plan
  const clean2dResponse = await ai.models.generateContent({
    model,
    contents: { parts: [imagePart, { text: prompt2d }] },
    config: { responseModalities: [Modality.IMAGE] },
  });

  let clean2dImagePart;
  for (const part of clean2dResponse.candidates[0].content.parts) {
    if (part.inlineData) {
      clean2dImagePart = { inlineData: { data: part.inlineData.data, mimeType: 'image/png' } };
      break;
    }
  }

  if (!clean2dImagePart) {
    throw new Error('Failed to create a clean 2D plan for 3D conversion.');
  }

  // Step 2: Convert clean 2D to 3D
  const prompt3d_step2 = `Convert this clean black-line floor plan into a 3D isometric architectural view while preserving 100% of the original geometry and proportions (no redesign). Pre-clean & vectorize: – Use only architectural geometry; remove text, dimensions, arrows, hatches, furniture, centerlines, symbols, annotations. – Bridge small gaps in wall lines: auto-close discontinuities up to 0.3% of the image width (or 10 px minimum). If a gap is larger, keep it as drawn. Walls (never miss): – Walls are pairs of parallel lines; infer wall thickness from their spacing. – Single thick line = center it and assign 200 mm thickness. – Exterior outline = thickest continuous loop; interior partitions = thinner pairs. – Snap endpoints to meet cleanly; enforce perpendicular/colinear continuity unless the drawing clearly shows an angle. – Ensure closed wall loops around rooms; do not leave unintended breaks. Openings (don’t invent, don’t miss): – Doors: gap in wall with swing arc or thin leaf rectangle; cut full wall thickness; head height 2.1 m. – Windows: thin rectangle or break along a wall; sill 0.9 m, head 2.1 m. – If a symbol is ambiguous or missing, keep the wall solid (never guess an opening). Stairs (critical rule — do NOT treat broken lines as walls): – Dashed/broken lines, break marks, or direction arrows within a stair zone are NOT walls or partitions. – Recognize stair zones by a series of parallel treads (short repeated lines) and/or an arrow indicating up/down. – Keep only the stair outline/stringers as solid geometry; ignore internal dashed centerlines, break-lines, or cut-plane markers for wall detection. – Extrude stairs as steps following the arrow direction (if present); otherwise infer rise from tread sequence. Other elements: – Columns/cores: closed small rectangles/circles = structural; extrude to ceiling. – Voids/courtyards/shafts: closed empty regions designated as voids remain open to sky. Extrusion & levels: – Floor slab 200 mm; default wall height 3.0 m. – Doors/windows cut walls precisely; no floating fragments. Camera & style: – Isometric/axonometric camera showing depth and volume. – Surfaces: neutral white/light-gray; no textures or furniture unless explicitly drawn. – Lighting: soft realistic shadows, even ambient; plain white background (no scene clutter). – Output: clean CAD-like 3D iso, crisp edges, high contrast, presentation-ready. Strict constraints: – Do not change room sizes, wall positions, or add/remove openings. – If any element is unclear, preserve solids and avoid assumptions. – Maintain exact alignment with the original plan layout.`;

  const final3dResponse = await ai.models.generateContent({
    model,
    contents: { parts: [clean2dImagePart, { text: prompt3d_step2 }] },
    config: { responseModalities: [Modality.IMAGE] },
  });

  for (const part of final3dResponse.candidates[0].content.parts) {
    if (part.inlineData) return part.inlineData.data;
  }
  throw new Error('3D floorplan generation failed.');
};

export const generateAdvertisement = async (details: string, language: string): Promise<string> => {
  const model = 'gemini-2.5-flash';
  const prompt = `Write a compelling and professional real estate advertisement in ${language} based on the following property details. The tone should be inviting and highlight the key features. Do not use asterisks (*) for formatting; use hyphens (-) for bullet points if needed.

Property Details:
${details}`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text;
};

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { generateImage } from '../services/geminiService';
import { UploadIcon, SparklesIcon, ResetIcon, DownloadIcon, CompareIcon, ExpandIcon, CloseIcon } from './icons';
import { EditMode, FurnitureOptionId, Style, Category, BuildingState, StyleSubCategory } from '../types';
import 'image-comparison-slider';

// Fix for custom element 'image-comparison-slider' not being recognized by TypeScript JSX.
const ImageComparisonSlider = 'image-comparison-slider' as any;

interface ImageEditorProps {
  activeCategory: Category['id'];
  onImageDoubleClick: (url: string) => void;
  selectedStyle: Style | null;
  geometryValue: number;
  selectedFurnitureOption: FurnitureOptionId;
  furniturePrompt: string;
  buildingState: BuildingState;
  editMode: EditMode;
  styleSubCategory?: StyleSubCategory;
  isMoodboard: boolean;
  contrastValue: number;
  onSetContrastValue: (value: number) => void;
  styleReferenceImage: File | null;
  // External props for AI Render mode
  externalResultUrl?: string | null;
  externalBaseUrl?: string | null;
  externalLoading?: boolean;
  externalError?: string | null;
}

export const ImageEditor: React.FC<ImageEditorProps> = ({
  activeCategory,
  onImageDoubleClick,
  selectedStyle,
  geometryValue,
  selectedFurnitureOption,
  furniturePrompt,
  buildingState,
  editMode,
  styleSubCategory,
  isMoodboard,
  contrastValue,
  onSetContrastValue,
  styleReferenceImage,
  externalResultUrl,
  externalBaseUrl,
  externalLoading,
  externalError,
}) => {
  const [originalImage, setOriginalImage] = useState<File | null>(null);
  const [originalImageUrl, setOriginalImageUrl] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isComparing, setIsComparing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Synchronize with external state (e.g., from AI Render mode)
  useEffect(() => {
    if (externalResultUrl) {
        setGeneratedImageUrl(externalResultUrl);
    }
  }, [externalResultUrl]);

  useEffect(() => {
    if (externalBaseUrl) {
        setOriginalImageUrl(externalBaseUrl);
    }
  }, [externalBaseUrl]);

  useEffect(() => {
    if (externalLoading !== undefined) {
        setIsLoading(externalLoading);
    }
  }, [externalLoading]);

  useEffect(() => {
    if (externalError !== undefined) {
        setError(externalError);
    }
  }, [externalError]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleImageReset = () => {
    setOriginalImage(null);
    setOriginalImageUrl(null);
    setGeneratedImageUrl(null);
    setError(null);
    setIsComparing(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  }

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      handleImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleGenerate = useCallback(async () => {
    if (!originalImage) return;

    setIsLoading(true);
    setError(null);
    setGeneratedImageUrl(null);
    setIsComparing(false);

    let finalPrompt = '';

    // Construction state instruction
    let buildingInstruction = '';
    if (buildingState === 'raw') {
      buildingInstruction = "The input image shows a raw construction state (unfinished concrete/brick shell, no paint, no tiles, no cladding, empty/unfinished pools). COMPLETELY FINISH the building: apply high-quality paints, cladding, flooring, and tiles to all surfaces. If a pool structure is present, tile it and fill it with water. Install windows/doors if missing, and landscape the surroundings. Transform this raw shell into a fully finished property. ";
    }

    if (editMode === 'prompt') {
      if (!prompt && !styleReferenceImage) {
          setError('Please enter a prompt or upload a style reference image.');
          setIsLoading(false);
          return;
      }
      finalPrompt = prompt;
    } else if (editMode === 'styles' && styleSubCategory === 'moodboard') {
        if (!styleReferenceImage) {
            setError('Please upload a moodboard image for reference.');
            setIsLoading(false);
            return;
        }

        // Note: furniturePrompt is intentionally excluded here to avoid conflicting with the strict moodboard instructions
        // which define their own furniture rules (maintain position, change materials).
        finalPrompt = `
          ${buildingInstruction}

          Use the uploaded base interior or exterior image as the primary reference and the uploaded moodboard image as the strict material and style guide.

          Replace all existing materials, textures, and color palettes in the base image with those shown in the moodboard, including:
          – wall finishes and colors
          – floor materials
          – ceiling materials and details
          – furniture materials and finishes
          – pool finishes and tiles (if present)

          Geometry preservation (critical):
          Keep the architecture, proportions, volumes, structure, openings, and camera angle exactly the same as the original image.
          Do not modify walls, floors, ceilings, roofs, openings, pool shape, or spatial layout.

          Furniture & accessories:
          – Maintain existing furniture positions and scale.
          – Change only materials, upholstery, finishes, and colors to match the moodboard.
          – Accessories (curtains, cushions, decor objects, small loose furniture) may be adjusted, replaced, or simplified only if necessary to align with the moodboard style.
          – Do not overcrowd the scene and do not introduce new dominant elements.

          Moodboard adherence (strict):
          – Use the moodboard as the sole reference for textures, materials, colors, and overall design language.
          – Match surface finishes, gloss/matte levels, wood grain direction, stone veining, fabric texture, and pool tile patterns accurately.
          – Do not invent styles, colors, or materials not present in the moodboard.

          Lighting & realism:
          – Create a high-end, editorial-quality architectural image.
          – Use soft, realistic lighting with natural shadows and balanced contrast.
          – Maintain a refined, luxury atmosphere suitable for an architectural presentation or client pitch.
          – Improve material realism, reflections, depth, and texture fidelity without altering the design.

          Output quality:
          – Ultra-realistic, professional architectural visualization
          – Clean, elegant, and presentation-ready
          – No artistic distortion, no stylization, no geometry changes
          – The final image must clearly read as the original project re-materialized according to the moodboard, at a premium architectural standard.
        `;
    } else if (selectedStyle) {
      finalPrompt = `${buildingInstruction}${furniturePrompt}in a ${selectedStyle.name} style, ${selectedStyle.prompt}`;
    } else {
        setError('Please select a style, upload a moodboard, or switch to prompt mode.');
        setIsLoading(false);
        return;
    }

    try {
      const base64String = await generateImage(originalImage, finalPrompt, geometryValue, contrastValue, styleReferenceImage);
      setGeneratedImageUrl(`data:image/png;base64,${base64String}`);
    } catch (e: any) {
      console.error(e);
      let errorMsg = e.message || 'An error occurred during image generation.';
      if (errorMsg.includes('429') || errorMsg.includes('quota') || errorMsg.includes('RESOURCE_EXHAUSTED')) {
        errorMsg = 'API Quota Exceeded. Please try again later or check your API plan.';
      } else if (errorMsg.includes('503')) {
        errorMsg = 'Service is temporarily unavailable. Please try again shortly.';
      }
      setError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  }, [originalImage, editMode, prompt, selectedStyle, furniturePrompt, geometryValue, contrastValue, styleReferenceImage, buildingState, styleSubCategory]);

  const handleDownload = () => {
    const url = generatedImageUrl || externalResultUrl;
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    link.download = `render-master-ai-${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const renderImageContainer = (isOutput: boolean) => {
    const imageUrl = isOutput ? (generatedImageUrl || externalResultUrl) : (originalImageUrl || externalBaseUrl);
    const title = isOutput ? "Generated Image" : "Original Image";

    if (isLoading && isOutput) {
        return (
            <div className="w-full h-full flex flex-col items-center justify-center bg-gray-100 rounded-lg shimmer-bg">
                <p className="mt-4 text-gray-800 font-bold text-lg z-10">Generating your vision...</p>
                <p className="text-gray-600 mt-1 z-10">This may take a moment.</p>
            </div>
        )
    }

    if (!imageUrl) {
        return (
            <div className={`w-full h-full flex items-center justify-center rounded-lg ${!isOutput ? 'bg-white border-2 border-dashed border-gray-300' : 'bg-gray-100'}`}>
                <div className="text-center text-gray-500 p-4">
                    {isOutput ? 'Your generated image will appear here.' : 'Upload an image to get started.'}
                </div>
            </div>
        )
    }

    return (
        <img
            src={imageUrl}
            alt={title}
            className="w-full h-full object-contain"
            onDoubleClick={() => onImageDoubleClick(imageUrl)}
        />
    )
  }

  const comparisonSlider = (
    <ImageComparisonSlider className="slider-with-custom-handle">
        <img slot="first" src={(originalImageUrl || externalBaseUrl)!} alt="Original" />
        <img slot="second" src={(generatedImageUrl || externalResultUrl)!} alt="Generated" />
        <div slot="handle" className="custom-handle">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24" fill="currentColor"><path d="M12 4l-1.41 1.41L16.17 11H4v2h12.17l-5.58 5.59L12 20l8-8z"/><path d="M12 20l-1.41-1.41L5.83 13H20v-2H5.83l5.58-5.59L12 4l-8 8z"/></svg>
        </div>
    </ImageComparisonSlider>
  );

  const isAIRenderMode = activeCategory === 'AI Render';
  const showSplitControls = !isAIRenderMode; 

  const getPlaceholderText = () => {
    if (editMode === 'prompt') return "Describe your vision (optional if style image provided)...";
    if (editMode === 'styles' && styleSubCategory === 'moodboard') return "Moodboard selected. Click Generate to apply style.";
    return "Style selected. Use the sidebar or switch to Prompt mode.";
  };

  return (
    <main className="flex-1 p-4 md:p-6 flex flex-col bg-gray-50 overflow-auto">
      <div className={`flex-1 ${isAIRenderMode ? 'flex' : 'grid grid-cols-1 md:grid-cols-2'} gap-4 md:gap-6 min-h-0`}>
        {/* Left Column: Image Upload & Original (Hidden in AI Render mode) */}
        {!isAIRenderMode && (
          <div
            className="relative w-full h-full flex items-center justify-center rounded-lg group"
            onDragOver={(e) => e.preventDefault()}
            onDrop={handleDrop}
          >
            {!(originalImageUrl || externalBaseUrl) ? (
               <div className="text-center p-6 cursor-pointer border-2 border-dashed border-gray-400 rounded-xl hover:bg-gray-100 transition-colors w-full h-full flex flex-col justify-center items-center" onClick={() => fileInputRef.current?.click()}>
                  <UploadIcon className="w-12 h-12 text-gray-400 mx-auto mb-4 breathing-icon" />
                  <h3 className="text-lg font-semibold text-gray-700">Drop your image here</h3>
                  <p className="text-gray-500">or click to browse</p>
                </div>
            ) : (
              <>
                <div className="absolute top-0 left-0 bg-black/50 text-white text-xs font-bold px-2 py-1 rounded-br-lg z-10">BEFORE</div>
                {renderImageContainer(false)}
                {!externalBaseUrl && (
                  <button onClick={handleImageReset} className="absolute top-2 right-2 bg-black/50 text-white p-1.5 rounded-full opacity-0 group-hover:opacity-100 transition-opacity" title="Clear Image">
                      <CloseIcon className="w-5 h-5" />
                  </button>
                )}
              </>
            )}
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
          </div>
        )}

        {/* Output Area (Generated Image) */}
        <div className="relative w-full h-full rounded-lg overflow-hidden flex-1">
            {externalResultUrl && <div className="absolute top-0 left-0 bg-indigo-600 text-white text-xs font-bold px-2 py-1 rounded-br-lg z-10 uppercase">AI Render Result</div>}
            {isComparing && (originalImageUrl || externalBaseUrl) && (generatedImageUrl || externalResultUrl) ? comparisonSlider : renderImageContainer(true)}
        </div>
      </div>

      {error && <div className="text-center text-red-500 font-semibold mt-4 px-4 py-2 bg-red-50 rounded-lg border border-red-200">{error}</div>}

      {/* Bottom controls - only show if not in external control mode like AI Render */}
      {showSplitControls && (
        <div className="shrink-0 pt-4 mt-4 border-t border-gray-200">
            <div className="mb-4">
            <label className="text-sm font-semibold text-gray-700 mb-2 block">Contrast</label>
            <input
                type="range"
                min="-50"
                max="50"
                value={contrastValue}
                onChange={(e) => onSetContrastValue(parseInt(e.target.value, 10))}
                className="w-full contrast-slider"
                style={{ '--progress': `${((contrastValue + 50) / 100) * 100}%` } as React.CSSProperties}
                disabled={isLoading}
            />
            </div>
            <div className="flex flex-col md:flex-row items-center gap-4">
            <div className="w-full flex-1">
                <input
                type="text"
                value={prompt}
                onChange={(e) => setPrompt(e.target.value)}
                placeholder={getPlaceholderText()}
                disabled={isLoading || editMode !== 'prompt'}
                className="w-full px-4 py-3 text-gray-800 bg-white rounded-lg border border-gray-300 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-colors"
                />
            </div>
            <div className="w-full md:w-auto flex items-center gap-2">
                <button
                onClick={handleGenerate}
                disabled={!originalImage || isLoading || isMoodboard}
                className="flex-1 flex items-center justify-center px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg shadow-md hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 text-base"
                >
                <SparklesIcon className={`w-5 h-5 mr-2 ${isLoading ? 'animate-spin' : ''}`} />
                {isLoading ? 'Generating...' : `Generate`}
                </button>
                <button onClick={handleImageReset} title="Reset" className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors" disabled={isLoading}><ResetIcon className="w-5 h-5"/></button>
                <button onClick={() => setIsComparing(!isComparing)} title="Compare" disabled={!(originalImageUrl || externalBaseUrl) || !(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><CompareIcon className="w-5 h-5"/></button>
                <button onClick={handleDownload} title="Download" disabled={!(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><DownloadIcon className="w-5 h-5"/></button>
                <button onClick={() => (generatedImageUrl || externalResultUrl) && onImageDoubleClick((generatedImageUrl || externalResultUrl)!)} title="Expand" disabled={!(generatedImageUrl || externalResultUrl)} className="p-3 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"><ExpandIcon className="w-5 h-5"/></button>
            </div>
            </div>
        </div>
      )}

      {isAIRenderMode && (generatedImageUrl || externalResultUrl) && (
        <div className="shrink-0 pt-4 mt-4 flex justify-center gap-4">
             <button onClick={() => setIsComparing(!isComparing)} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <CompareIcon className="w-5 h-5" />
                Compare Before/After
             </button>
             <button onClick={handleDownload} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <DownloadIcon className="w-5 h-5" />
                Download Render
             </button>
             <button onClick={() => onImageDoubleClick((generatedImageUrl || externalResultUrl)!)} className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-300 rounded-lg font-semibold hover:bg-gray-50 transition-all hover:shadow-md active:scale-95">
                <ExpandIcon className="w-5 h-5" />
                Full Screen
             </button>
        </div>
      )}
    </main>
  );
};

import React, { useRef } from 'react';
import { CATEGORIES, FURNITURE_OPTIONS, CONCEPTUAL_STYLES, ART_STYLES, EXTERIOR_RENDER_STYLES, FLOORPLAN_STYLES } from '../constants';
import { Category, Style, FurnitureOptionId, EditMode, StyleSubCategory, AIRenderMode, User, BuildingState } from '../types';
import { CnjImages } from './CnjImages';
import { GeometrySlider } from './GeometrySlider';
import { UploadIcon, CloseIcon, SparklesIcon } from './icons';

interface SidebarProps {
  activeCategory: Category['id'];
  onCategoryClick: (id: Category['id']) => void;
  selectedStyleId: Style['id'] | null;
  onApplyStyle: (style: Style | null) => void;
  geometryValue: number;
  onSetGeometryValue: (value: number) => void;
  selectedFurnitureOption: FurnitureOptionId;
  onSetFurnitureOption: (option: FurnitureOptionId) => void;
  buildingState?: BuildingState;
  onSetBuildingState?: (state: BuildingState) => void;
  editMode: EditMode;
  onSetEditMode: (mode: EditMode) => void;
  styleSubCategory: StyleSubCategory;
  onSetStyleSubCategory: (category: StyleSubCategory) => void;
  styleReferenceImageUrl: string | null;
  onStyleReferenceImageChange: (file: File | null) => void;
  aiRenderBaseImageUrl: string | null;
  onAiRenderBaseImageChange: (file: File | null) => void;
  aiRenderMode: AIRenderMode;
  onSetAiRenderMode: (mode: AIRenderMode) => void;
  aiRenderCreativity: number;
  onSetAiRenderCreativity: (value: number) => void;
  onAIRenderGenerate: () => void;
  isAiRenderLoading: boolean;
  user: User | null;
  // Floorplan specific props
  floorplanBaseImageUrl?: string | null;
  onFloorplanBaseImageChange?: (file: File | null) => void;
  onFloorplanGenerate?: () => void;
  isFloorplanLoading?: boolean;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  activeCategory, 
  onCategoryClick,
  selectedStyleId, 
  onApplyStyle,
  geometryValue,
  onSetGeometryValue,
  selectedFurnitureOption,
  onSetFurnitureOption,
  buildingState = 'ready',
  onSetBuildingState,
  editMode,
  onSetEditMode,
  styleSubCategory,
  onSetStyleSubCategory,
  styleReferenceImageUrl,
  onStyleReferenceImageChange,
  aiRenderBaseImageUrl,
  onAiRenderBaseImageChange,
  aiRenderMode,
  onSetAiRenderMode,
  aiRenderCreativity,
  onSetAiRenderCreativity,
  onAIRenderGenerate,
  isAiRenderLoading,
  user,
  floorplanBaseImageUrl,
  onFloorplanBaseImageChange,
  onFloorplanGenerate,
  isFloorplanLoading,
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const aiRenderFileInputRef = useRef<HTMLInputElement>(null);
  const floorplanFileInputRef = useRef<HTMLInputElement>(null);
  const exteriorConceptualStyles = CONCEPTUAL_STYLES.filter(style => style.id !== 'conceptual-night');

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
        onStyleReferenceImageChange(e.target.files[0]);
    }
  };

  const handleAiRenderFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
        onAiRenderBaseImageChange(e.target.files[0]);
    }
  };

  const handleFloorplanFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0] && onFloorplanBaseImageChange) {
        onFloorplanBaseImageChange(e.target.files[0]);
    }
  };

  const renderMoodboardUpload = () => (
      <div className="mt-4">
        <h3 className="text-sm font-semibold text-gray-900 mb-3 uppercase tracking-wider">Reference Moodboard</h3>
        <div 
            onClick={() => fileInputRef.current?.click()}
            className="relative border-2 border-dashed border-gray-300 rounded-xl p-4 flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition-colors h-48 group overflow-hidden"
        >
            {styleReferenceImageUrl ? (
                <>
                    <img src={styleReferenceImageUrl} alt="Moodboard Reference" className="absolute inset-0 w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                        <span className="text-white text-xs font-bold bg-indigo-600 px-3 py-1.5 rounded-full">Change Image</span>
                    </div>
                </>
            ) : (
                <>
                    <UploadIcon className="w-10 h-10 text-gray-400 mb-2 breathing-icon" />
                    <span className="text-xs text-gray-500 font-medium">Upload Moodboard</span>
                </>
            )}
        </div>
        <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            className="hidden" 
            accept="image/*"
        />
        <p className="text-xs text-gray-500 mt-2">Upload an image to copy its style, colors, and materials.</p>
    </div>
  );

  return (
    <aside className="w-full md:w-96 bg-gray-100 p-6 flex flex-col space-y-8 overflow-y-auto shrink-0 border-r border-gray-200 no-scrollbar">
      <div>
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Scene</h2>
        <div className="flex flex-wrap items-center bg-white rounded-lg p-1 border border-gray-200 gap-1">
          {CATEGORIES.map(({ id, Icon, isPro }) => (
            <button
              key={id}
              onClick={() => onCategoryClick(id)}
              className={`relative flex-1 flex items-center justify-center gap-2 p-2 rounded-md text-[10px] md:text-xs font-medium transition-colors ${
                activeCategory === id ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
              }`}
            >
              <Icon className="w-4 h-4" />
              {id}
              {isPro && user?.plan === 'free' && (
                <span className="absolute -top-1.5 -right-1 bg-yellow-400 text-indigo-950 text-[8px] px-1 rounded-sm font-bold shadow-sm">PRO</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {activeCategory === 'Floorplan' ? (
        <div className="space-y-6">
            <div>
                <h3 className="text-sm font-semibold text-gray-900 mb-3 uppercase tracking-wider">Base Floorplan / Sketch</h3>
                <div 
                    onClick={() => floorplanFileInputRef.current?.click()}
                    className="relative border-2 border-dashed border-gray-300 rounded-xl p-4 flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition-colors h-48 group overflow-hidden"
                >
                    {floorplanBaseImageUrl ? (
                        <>
                            <img src={floorplanBaseImageUrl} alt="Base floorplan" className="absolute inset-0 w-full h-full object-cover" />
                            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                <span className="text-white text-xs font-bold bg-indigo-600 px-3 py-1.5 rounded-full">Change Image</span>
                            </div>
                        </>
                    ) : (
                        <>
                            <UploadIcon className="w-10 h-10 text-gray-400 mb-2 breathing-icon" />
                            <span className="text-xs text-gray-500 font-medium">Upload Floorplan or Sketch</span>
                        </>
                    )}
                </div>
                <input 
                    type="file" 
                    ref={floorplanFileInputRef} 
                    onChange={handleFloorplanFileChange} 
                    className="hidden" 
                    accept="image/*"
                />
            </div>

            <GeometrySlider value={geometryValue} onChange={onSetGeometryValue} />

            <div>
                <h3 className="text-sm font-semibold text-gray-900 mb-3 uppercase tracking-wider">Floorplan Styles</h3>
                <div className="grid grid-cols-2 gap-4">
                  {FLOORPLAN_STYLES.map((style) => (
                    <CnjImages
                      key={style.id}
                      src={style.image}
                      alt={style.name}
                      isSelected={selectedStyleId === style.id}
                      onClick={() => onApplyStyle(style)}
                    />
                  ))}
                </div>
            </div>

            <button
                onClick={onFloorplanGenerate}
                disabled={!floorplanBaseImageUrl || !selectedStyleId || isFloorplanLoading}
                className="w-full flex items-center justify-center px-6 py-4 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 transform active:scale-95"
            >
                {isFloorplanLoading ? (
                    <SparklesIcon className="w-5 h-5 mr-2 animate-spin" />
                ) : (
                    <SparklesIcon className="w-5 h-5 mr-2" />
                )}
                {isFloorplanLoading ? 'Generating Plan...' : 'Generate Floorplan'}
            </button>
            {user?.plan === 'free' && (
              <p className="text-center text-[10px] text-gray-500">
                You have {user.credits} credits remaining this month.
              </p>
            )}
        </div>
      ) : activeCategory === 'AI Render' ? (
        <div className="space-y-6">
            <div>
                <h3 className="text-sm font-semibold text-gray-900 mb-3 uppercase tracking-wider">Base Image / Sketch</h3>
                <div 
                    onClick={() => aiRenderFileInputRef.current?.click()}
                    className="relative border-2 border-dashed border-gray-300 rounded-xl p-4 flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition-colors h-48 group overflow-hidden"
                >
                    {aiRenderBaseImageUrl ? (
                        <>
                            <img src={aiRenderBaseImageUrl} alt="Base image" className="absolute inset-0 w-full h-full object-cover" />
                            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                <span className="text-white text-xs font-bold bg-indigo-600 px-3 py-1.5 rounded-full">Change Image</span>
                            </div>
                        </>
                    ) : (
                        <>
                            <UploadIcon className="w-10 h-10 text-gray-400 mb-2 breathing-icon" />
                            <span className="text-xs text-gray-500 font-medium">Upload Image or Sketch</span>
                        </>
                    )}
                </div>
                <input 
                    type="file" 
                    ref={aiRenderFileInputRef} 
                    onChange={handleAiRenderFileChange} 
                    className="hidden" 
                    accept="image/*"
                />
            </div>

            <div>
                <h3 className="text-sm font-semibold text-gray-900 mb-3 uppercase tracking-wider">Render Mode</h3>
                <div className="flex bg-white rounded-lg p-1 border border-gray-200">
                    <button
                        onClick={() => onSetAiRenderMode('keep-texture')}
                        className={`flex-1 p-2 rounded-md text-xs font-medium transition-colors ${
                            aiRenderMode === 'keep-texture' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                        }`}
                    >
                        Keep texture
                    </button>
                    <button
                        onClick={() => onSetAiRenderMode('creative')}
                        className={`flex-1 p-2 rounded-md text-xs font-medium transition-colors ${
                            aiRenderMode === 'creative' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                        }`}
                    >
                        Creative
                    </button>
                </div>
            </div>

            <div>
                <div className="flex items-center justify-between mb-2">
                    <h3 className="text-sm font-semibold text-gray-900 uppercase tracking-wider">Creativity Level</h3>
                    <span className="text-indigo-600 font-bold text-sm">{aiRenderCreativity}</span>
                </div>
                <div className="bg-white p-4 rounded-lg border border-gray-200">
                    <input
                        type="range"
                        min="1"
                        max="10"
                        step="1"
                        value={aiRenderCreativity}
                        onChange={(e) => onSetAiRenderCreativity(parseInt(e.target.value, 10))}
                        className="w-full contrast-slider"
                        style={{ '--progress': `${((aiRenderCreativity - 1) / 9) * 100}%` } as React.CSSProperties}
                        disabled={isAiRenderLoading}
                    />
                </div>
            </div>

            <button
                onClick={onAIRenderGenerate}
                disabled={!aiRenderBaseImageUrl || isAiRenderLoading}
                className="w-full flex items-center justify-center px-6 py-4 bg-indigo-600 text-white font-bold rounded-xl shadow-lg hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 transform active:scale-95"
            >
                {isAiRenderLoading ? (
                    <SparklesIcon className="w-5 h-5 mr-2 animate-spin" />
                ) : (
                    <SparklesIcon className="w-5 h-5 mr-2" />
                )}
                {isAiRenderLoading ? 'Rendering...' : 'Generate Render'}
            </button>
            {user?.plan === 'free' && (
              <p className="text-center text-[10px] text-gray-500">
                You have {user.credits} credits remaining this month.
              </p>
            )}
        </div>
      ) : activeCategory !== 'Moodboard' ? (
        <>
          <GeometrySlider value={geometryValue} onChange={onSetGeometryValue} />

          {/* Raw vs Ready Building Toggle */}
          {onSetBuildingState && (
             <div className="mb-2">
                <div className="flex bg-white rounded-lg p-1 border border-gray-200">
                    <button
                        onClick={() => onSetBuildingState('raw')}
                        className={`flex-1 p-2 rounded-md text-xs font-medium transition-colors ${
                            buildingState === 'raw' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                        }`}
                    >
                        Raw Building
                    </button>
                    <button
                        onClick={() => onSetBuildingState('ready')}
                        className={`flex-1 p-2 rounded-md text-xs font-medium transition-colors ${
                            buildingState === 'ready' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                        }`}
                    >
                        Ready Building
                    </button>
                </div>
             </div>
          )}

          {/* ... Rest of Sidebar content ... */}
          {activeCategory === 'Interiors' ? (
            <>
              <div>
                <h2 className="text-lg font-semibold text-gray-900 mb-4">Furniture</h2>
                <div className="space-y-2">
                  {FURNITURE_OPTIONS.map((option) => (
                    <button
                      key={option.id}
                      onClick={() => onSetFurnitureOption(option.id)}
                      className={`w-full text-left flex items-center gap-3 p-3 rounded-lg transition-colors border ${
                        selectedFurnitureOption === option.id
                          ? 'bg-indigo-100 border-indigo-300 ring-1 ring-indigo-300'
                          : 'bg-white hover:bg-gray-200/60 border-gray-200'
                      }`}
                    >
                      <option.Icon className={`w-5 h-5 flex-shrink-0 ${selectedFurnitureOption === option.id ? 'text-indigo-600' : 'text-indigo-400'}`} />
                      <span className={`text-sm ${selectedFurnitureOption === option.id ? 'font-semibold text-gray-800' : 'text-gray-700'}`}>{option.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex items-center bg-white rounded-lg p-1 border border-gray-200 mb-4">
                  <button
                    onClick={() => onSetEditMode('conceptual')}
                    className={`w-full p-2 rounded-md text-sm font-medium transition-colors uppercase tracking-wider ${
                      editMode === 'conceptual' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    Conceptual
                  </button>
                  <button
                    onClick={() => onSetEditMode('styles')}
                    className={`w-full p-2 rounded-md text-sm font-medium transition-colors uppercase tracking-wider ${
                      editMode === 'styles' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    Styles
                  </button>
                  <button
                    onClick={() => onSetEditMode('prompt')}
                    className={`w-full p-2 rounded-md text-sm font-medium transition-colors uppercase tracking-wider ${
                      editMode === 'prompt' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    Prompt
                  </button>
                </div>

                {editMode === 'conceptual' && (
                  <div className="grid grid-cols-2 gap-4">
                    {CONCEPTUAL_STYLES.map((style) => (
                      <CnjImages
                        key={style.id}
                        src={style.image}
                        alt={style.name}
                        isSelected={selectedStyleId === style.id}
                        onClick={() => onApplyStyle(style)}
                      />
                    ))}
                  </div>
                )}

                {editMode === 'styles' && (
                  <div>
                    {/* Interior Sub-category toggle */}
                    <div className="flex items-center bg-white rounded-lg p-1 border border-gray-200 mb-4">
                        <button
                            onClick={() => { onSetStyleSubCategory('preset'); onApplyStyle(null); }}
                            className={`w-full p-2 rounded-md text-sm font-medium transition-colors ${
                                styleSubCategory === 'preset' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                            }`}
                        >
                            PRE-SET
                        </button>
                        <button
                            onClick={() => { onSetStyleSubCategory('moodboard'); onApplyStyle(null); }}
                            className={`w-full p-2 rounded-md text-sm font-medium transition-colors ${
                                styleSubCategory === 'moodboard' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                            }`}
                        >
                            MOODBOARD
                        </button>
                    </div>

                    {styleSubCategory === 'preset' && (
                        <div className="grid grid-cols-2 gap-4">
                            {ART_STYLES.map((style) => (
                            <CnjImages
                                key={style.id}
                                src={style.image}
                                alt={style.name}
                                isSelected={selectedStyleId === style.id}
                                onClick={() => onApplyStyle(style)}
                            />
                            ))}
                        </div>
                    )}

                    {styleSubCategory === 'moodboard' && renderMoodboardUpload()}
                  </div>
                )}
              </div>
            </>
          ) : ( // Exteriors logic
            <div>
               <div className="flex items-center bg-white rounded-lg p-1 border border-gray-200 mb-4">
                <button
                  onClick={() => onSetEditMode('conceptual')}
                  className={`w-full p-2 rounded-md text-sm font-medium transition-colors uppercase tracking-wider ${
                    editMode === 'conceptual' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                  }`}
                >
                  Render
                </button>
                <button
                  onClick={() => onSetEditMode('styles')}
                  className={`w-full p-2 rounded-md text-sm font-medium transition-colors uppercase tracking-wider ${
                    editMode === 'styles' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                  }`}
                >
                  Styles
                </button>
                <button
                  onClick={() => onSetEditMode('prompt')}
                  className={`w-full p-2 rounded-md text-sm font-medium transition-colors uppercase tracking-wider ${
                    editMode === 'prompt' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                  }`}
                >
                  Prompt
                </button>
              </div>

              {editMode === 'conceptual' && (
                <div>
                  <h2 className="text-lg font-semibold text-gray-900 mb-4">Render Modes</h2>
                  <div className="grid grid-cols-2 gap-4">
                    {EXTERIOR_RENDER_STYLES.map((style) => (
                      <CnjImages
                        key={style.id}
                        src={style.image}
                        alt={style.name}
                        isSelected={selectedStyleId === style.id}
                        onClick={() => onApplyStyle(style)}
                      />
                    ))}
                  </div>
                </div>
              )}

              {editMode === 'styles' && (
                <div>
                    <h2 className="text-lg font-semibold text-gray-900 mb-4">Styles</h2>
                    <div className="flex items-center bg-white rounded-lg p-1 border border-gray-200 mb-4 overflow-x-auto no-scrollbar">
                      <button
                        onClick={() => { onSetStyleSubCategory('preset'); onApplyStyle(null); }}
                        className={`flex-1 min-w-[70px] p-2 rounded-md text-[11px] font-medium transition-colors whitespace-nowrap ${
                          styleSubCategory === 'preset' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        PRE-SET
                      </button>
                      <button
                        onClick={() => { onSetStyleSubCategory('conceptual'); onApplyStyle(null); }}
                        className={`flex-1 min-w-[70px] p-2 rounded-md text-[11px] font-medium transition-colors whitespace-nowrap ${
                          styleSubCategory === 'conceptual' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        CONCEPTUAL
                      </button>
                      <button
                        onClick={() => { onSetStyleSubCategory('moodboard'); onApplyStyle(null); }}
                        className={`flex-1 min-w-[70px] p-2 rounded-md text-[11px] font-medium transition-colors whitespace-nowrap ${
                          styleSubCategory === 'moodboard' ? 'bg-indigo-600 text-white' : 'text-gray-600 hover:bg-gray-200'
                        }`}
                      >
                        MOODBOARD
                      </button>
                    </div>

                    {styleSubCategory === 'preset' && (
                      <div className="grid grid-cols-2 gap-4">
                        {ART_STYLES.map((style) => (
                          <CnjImages
                            key={style.id}
                            src={style.image}
                            alt={style.name}
                            isSelected={selectedStyleId === style.id}
                            onClick={() => onApplyStyle(style)}
                          />
                        ))}
                      </div>
                    )}
                    {styleSubCategory === 'conceptual' && (
                      <div className="grid grid-cols-2 gap-4">
                        {exteriorConceptualStyles.map((style) => (
                          <CnjImages
                            key={style.id}
                            src={style.image}
                            alt={style.name}
                            isSelected={selectedStyleId === style.id}
                            onClick={() => onApplyStyle(style)}
                          />
                        ))}
                      </div>
                    )}
                    {styleSubCategory === 'moodboard' && renderMoodboardUpload()}
                </div>
              )}
            </div>
          )}
        </>
      ) : (
        <div className="text-center p-4 bg-white rounded-lg border border-gray-200">
          <p className="text-sm text-gray-600 font-medium">Moodboard Mode</p>
        </div>
      )}
    </aside>
  );
};

import React, { useState, useRef } from 'react';
import { generateMoodboard } from '../services/geminiService';
import { UploadIcon, SparklesIcon, ResetIcon, DownloadIcon, CloseIcon } from './icons';

const MAX_IMAGES = 6;

interface MoodboardCreatorProps {
  onImageDoubleClick: (url: string) => void;
}

export const MoodboardCreator: React.FC<MoodboardCreatorProps> = ({ onImageDoubleClick }) => {
  const [sourceImages, setSourceImages] = useState<File[]>([]);
  const [sourceImageUrls, setSourceImageUrls] = useState<string[]>([]);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = (Array.from(e.target.files || []) as File[]).slice(0, MAX_IMAGES - sourceImages.length);
    if (files.length > 0) {
      setSourceImages(prev => [...prev, ...files]);
      const newUrls = files.map(file => URL.createObjectURL(file));
      setSourceImageUrls(prev => [...prev, ...newUrls]);
    }
  };

  const removeImage = (index: number) => {
    URL.revokeObjectURL(sourceImageUrls[index]);
    setSourceImages(prev => prev.filter((_, i) => i !== index));
    setSourceImageUrls(prev => prev.filter((_, i) => i !== index));
  };

  const handleGenerate = async () => {
    if (sourceImages.length === 0) return;

    setIsLoading(true);
    setError(null);
    try {
      const base64String = await generateMoodboard(sourceImages);
      setGeneratedImageUrl(`data:image/png;base64,${base64String}`);
    } catch (e: any) {
      console.error(e);
      let errorMsg = e.message || 'An error occurred during moodboard generation.';
      if (errorMsg.includes('429') || errorMsg.includes('quota') || errorMsg.includes('RESOURCE_EXHAUSTED')) {
        errorMsg = 'API Quota Exceeded. Please try again later or check your API plan.';
      } else if (errorMsg.includes('503')) {
        errorMsg = 'Service is temporarily unavailable. Please try again shortly.';
      }
      setError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleReset = () => {
    sourceImageUrls.forEach(url => URL.revokeObjectURL(url));
    setSourceImages([]);
    setSourceImageUrls([]);
    setGeneratedImageUrl(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleDownload = () => {
    if (!generatedImageUrl) return;
    const link = document.createElement('a');
    link.href = generatedImageUrl;
    link.download = 'moodboard.png';
    link.click();
  };

  return (
    <main className="flex-1 p-6 flex flex-col items-center justify-center bg-white overflow-auto">
        <div className="text-center mb-6">
            <h1 className="text-3xl font-bold text-gray-900">Moodboard Generator</h1>
            <p className="text-lg text-gray-600 mt-1">Upload 1 to 6 images to create a visual theme.</p>
        </div>
        <div className="w-full max-w-6xl flex-1 md:grid md:grid-cols-2 md:gap-8 space-y-6 md:space-y-0">
            {/* Left side */}
            <div className="flex flex-col h-full">
                <div className="grid grid-cols-3 gap-4 mb-4">
                    {sourceImageUrls.map((url, index) => (
                        <div key={index} className="relative aspect-square">
                            <img src={url} alt={`source ${index + 1}`} className="w-full h-full object-cover rounded-lg"/>
                            <button onClick={() => removeImage(index)} className="absolute top-1 right-1 bg-black/50 text-white p-1 rounded-full hover:bg-black/80">
                                <CloseIcon className="w-4 h-4" />
                            </button>
                        </div>
                    ))}
                    {sourceImages.length < MAX_IMAGES && (
                        <div 
                            className="flex items-center justify-center aspect-square border-2 border-dashed border-gray-300 rounded-lg cursor-pointer hover:bg-gray-100"
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <div className="text-center text-gray-500">
                                <UploadIcon className="w-8 h-8 mx-auto"/>
                                <span className="text-xs mt-1 block">Add Image</span>
                            </div>
                        </div>
                    )}
                </div>
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={handleFileChange} 
                    multiple 
                    accept="image/*" 
                    className="hidden"
                    disabled={sourceImages.length >= MAX_IMAGES}
                />

                <div className="flex items-center gap-4 mt-auto">
                    <button
                        onClick={handleGenerate}
                        disabled={sourceImages.length === 0 || isLoading}
                        className="flex-1 flex items-center justify-center px-6 py-4 bg-indigo-600 text-white font-semibold rounded-lg shadow-md hover:bg-indigo-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 text-lg"
                    >
                        <SparklesIcon className={`w-6 h-6 mr-3 ${isLoading ? 'animate-spin' : ''}`} />
                         {isLoading ? 'Generating...' : `Generate`}
                    </button>
                    <button onClick={handleReset} className="p-4 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors" title="Reset">
                        <ResetIcon className="w-6 h-6" />
                    </button>
                </div>
            </div>

            {/* Right side */}
            <div className="flex flex-col items-center justify-center border-2 border-dashed border-gray-300 rounded-lg bg-white relative h-full min-h-[300px] md:min-h-0">
                {isLoading ? (
                    <div className="text-center text-gray-500">
                        <SparklesIcon className="w-12 h-12 mx-auto mb-4 animate-spin"/>
                        <p>Generating moodboard...</p>
                    </div>
                ) : generatedImageUrl ? (
                    <>
                        <img onDoubleClick={() => onImageDoubleClick(generatedImageUrl)} src={generatedImageUrl} alt="Generated Moodboard" className="max-w-full max-h-full object-contain rounded-lg p-2 cursor-pointer" />
                        <button onClick={handleDownload} className="absolute top-4 right-4 bg-black/50 p-2 rounded-full text-white hover:bg-black/70 transition-colors" title="Download Image">
                            <DownloadIcon className="w-5 h-5" />
                        </button>
                    </>
                ) : (
                    <p className="text-gray-400">Your generated moodboard will appear here.</p>
                )}
            </div>
        </div>
        {error && <p className="text-red-600 text-sm mt-4 text-center px-4 py-2 bg-red-50 rounded-lg border border-red-200">{error}</p>}
    </main>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Header } from './components/Header';
import { Sidebar } from './components/Sidebar';
import { ImageEditor } from './components/ImageEditor';
import { HomeScreen } from './components/HomeScreen';
import { ImageViewerModal } from './components/ComparisonSliderModal';
import { MoodboardCreator } from './components/MoodboardCreator';
import PaymentPage from './components/PaymentPage';
import { Category, Style, FurnitureOptionId, EditMode, StyleSubCategory, User, SubscriptionPlan, AIRenderMode, UserProfile, BuildingState } from './types';
import { FURNITURE_OPTIONS, CATEGORIES } from './constants';
import { generateImage } from './services/geminiService';

function App() {
  // Auth & Subscription State
  const [user, setUser] = useState<User | null>(null);
  const [showPayment, setShowPayment] = useState(false);

  // Main editor state
  const [activeCategory, setActiveCategory] = useState<Category['id']>('Interiors');
  const [selectedStyle, setSelectedStyle] = useState<Style | null>(null);
  const [geometryValue, setGeometryValue] = useState(50);
  const [selectedFurnitureOption, setSelectedFurnitureOption] = useState<FurnitureOptionId>('change');
  const [buildingState, setBuildingState] = useState<BuildingState>('ready');
  const [editMode, setEditMode] = useState<EditMode>('conceptual');
  const [styleSubCategory, setStyleSubCategory] = useState<StyleSubCategory>('preset');
  const [contrastValue, setContrastValue] = useState(0);

  // Style Reference Image state
  const [styleReferenceImage, setStyleReferenceImage] = useState<File | null>(null);
  const [styleReferenceImageUrl, setStyleReferenceImageUrl] = useState<string | null>(null);

  // AI Render State
  const [aiRenderBaseImage, setAiRenderBaseImage] = useState<File | null>(null);
  const [aiRenderBaseImageUrl, setAiRenderBaseImageUrl] = useState<string | null>(null);
  const [aiRenderMode, setAiRenderMode] = useState<AIRenderMode>('creative');
  const [aiRenderCreativity, setAiRenderCreativity] = useState(5);
  const [aiRenderResultUrl, setAiRenderResultUrl] = useState<string | null>(null);
  const [isAiRenderLoading, setIsAiRenderLoading] = useState(false);
  const [aiRenderError, setAiRenderError] = useState<string | null>(null);

  // Floorplan State
  const [floorplanBaseImage, setFloorplanBaseImage] = useState<File | null>(null);
  const [floorplanBaseImageUrl, setFloorplanBaseImageUrl] = useState<string | null>(null);
  const [floorplanResultUrl, setFloorplanResultUrl] = useState<string | null>(null);
  const [isFloorplanLoading, setIsFloorplanLoading] = useState(false);
  const [floorplanError, setFloorplanError] = useState<string | null>(null);

  // Modal state
  const [isImageViewerOpen, setIsImageViewerOpen] = useState(false);
  const [viewerImageUrl, setViewerImageUrl] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const savedUser = localStorage.getItem('rm_user');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('rm_user', JSON.stringify(userData));
  };

  const handleProfileSelect = (profile: UserProfile) => {
    // Simulate direct login based on profile selection
    const isPro = profile === 'arkitecna';
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      email: isPro ? 'studio@arkitecna.com' : 'guest@example.com',
      name: isPro ? 'Arkitecna Studio' : 'Guest User',
      plan: isPro ? 'pro' : 'free',
      credits: isPro ? 1000 : 5,
    };
    handleLogin(newUser);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('rm_user');
    resetEditorState();
  };

  const handleUpgrade = (plan: SubscriptionPlan) => {
    if (user) {
      const updatedUser = { ...user, plan };
      setUser(updatedUser);
      localStorage.setItem('rm_user', JSON.stringify(updatedUser));
      setShowPayment(false);
    }
  };

  const handleCategoryClick = (id: Category['id']) => {
    const category = CATEGORIES.find(c => c.id === id);
    if (category?.isPro && (!user || user.plan === 'free')) {
      setShowPayment(true);
      return;
    }
    setActiveCategory(id);
    setSelectedStyle(null);
    setEditMode('conceptual');
    setBuildingState('ready'); // Reset building state on category change
    setStyleSubCategory('preset');
  };

  const handleStyleReferenceImageChange = (file: File | null) => {
    if (styleReferenceImageUrl) URL.revokeObjectURL(styleReferenceImageUrl);
    if (file) {
      setStyleReferenceImage(file);
      setStyleReferenceImageUrl(URL.createObjectURL(file));
    } else {
      setStyleReferenceImage(null);
      setStyleReferenceImageUrl(null);
    }
  };

  const handleAiRenderBaseImageChange = (file: File | null) => {
    if (aiRenderBaseImageUrl) URL.revokeObjectURL(aiRenderBaseImageUrl);
    if (file) {
      setAiRenderBaseImage(file);
      setAiRenderBaseImageUrl(URL.createObjectURL(file));
    } else {
      setAiRenderBaseImage(null);
      setAiRenderBaseImageUrl(null);
    }
    setAiRenderResultUrl(null);
    setAiRenderError(null);
  };

  const handleFloorplanBaseImageChange = (file: File | null) => {
    if (floorplanBaseImageUrl) URL.revokeObjectURL(floorplanBaseImageUrl);
    if (file) {
      setFloorplanBaseImage(file);
      setFloorplanBaseImageUrl(URL.createObjectURL(file));
    } else {
      setFloorplanBaseImage(null);
      setFloorplanBaseImageUrl(null);
    }
    setFloorplanResultUrl(null);
    setFloorplanError(null);
  };

  const resetEditorState = () => {
    setActiveCategory('Interiors');
    setSelectedStyle(null);
    setGeometryValue(50);
    setSelectedFurnitureOption('change');
    setBuildingState('ready');
    setEditMode('conceptual');
    setStyleSubCategory('preset');
    setContrastValue(0);
    handleStyleReferenceImageChange(null);
    handleAiRenderBaseImageChange(null);
    handleFloorplanBaseImageChange(null);
    setShowPayment(false);
  };

  const handleAIRenderGenerate = async () => {
    if (!aiRenderBaseImage || !user) return;

    if (user.plan === 'free' && user.credits <= 0) {
      setShowPayment(true);
      return;
    }

    setIsAiRenderLoading(true);
    setAiRenderError(null);

    let prompt = aiRenderMode === 'keep-texture' 
      ? "Professionally render this architectural image, keeping the existing textures..."
      : "Creatively render this architectural image...";

    const geometryValue = (10 - aiRenderCreativity) * 10;

    try {
        const base64 = await generateImage(aiRenderBaseImage, prompt, geometryValue, 0);
        setAiRenderResultUrl(`data:image/png;base64,${base64}`);

        // Use credit
        if (user.plan === 'free') {
          const updatedUser = { ...user, credits: user.credits - 1 };
          setUser(updatedUser);
          localStorage.setItem('rm_user', JSON.stringify(updatedUser));
        }
    } catch (e: any) {
        setAiRenderError(e.message || "Failed to generate render.");
    } finally {
        setIsAiRenderLoading(false);
    }
  };

  const handleFloorplanGenerate = async () => {
    if (!floorplanBaseImage || !user || !selectedStyle) return;

    if (user.plan === 'free' && user.credits <= 0) {
      setShowPayment(true);
      return;
    }

    setIsFloorplanLoading(true);
    setFloorplanError(null);

    try {
      // Use existing generateImage function but with floorplan specific prompt and geometry value
      const base64 = await generateImage(floorplanBaseImage, selectedStyle.prompt, geometryValue, 0);
      setFloorplanResultUrl(`data:image/png;base64,${base64}`);

      // Use credit
      if (user.plan === 'free') {
        const updatedUser = { ...user, credits: user.credits - 1 };
        setUser(updatedUser);
        localStorage.setItem('rm_user', JSON.stringify(updatedUser));
      }
    } catch (e: any) {
      setFloorplanError(e.message || "Failed to generate floorplan.");
    } finally {
      setIsFloorplanLoading(false);
    }
  };

  if (!user) {
    return <HomeScreen onProfileSelect={handleProfileSelect} />;
  }

  if (showPayment) {
    return <PaymentPage onSelectPlan={handleUpgrade} onBack={() => setShowPayment(false)} />;
  }

  return (
    <div className="h-screen w-screen flex flex-col bg-white font-sans antialiased">
      <Header onGoHome={resetEditorState} user={user} onLogout={handleLogout} />

      <div className="flex flex-col md:flex-row flex-1 min-h-0">
          <Sidebar
            activeCategory={activeCategory}
            onCategoryClick={handleCategoryClick}
            selectedStyleId={selectedStyle?.id || null}
            onApplyStyle={(s) => setSelectedStyle(s)}
            geometryValue={geometryValue}
            onSetGeometryValue={setGeometryValue}
            selectedFurnitureOption={selectedFurnitureOption}
            onSetFurnitureOption={setSelectedFurnitureOption}
            buildingState={buildingState}
            onSetBuildingState={setBuildingState}
            editMode={editMode}
            onSetEditMode={setEditMode}
            styleSubCategory={styleSubCategory}
            onSetStyleSubCategory={setStyleSubCategory}
            styleReferenceImageUrl={styleReferenceImageUrl}
            onStyleReferenceImageChange={handleStyleReferenceImageChange}
            aiRenderBaseImageUrl={aiRenderBaseImageUrl}
            onAiRenderBaseImageChange={handleAiRenderBaseImageChange}
            aiRenderMode={aiRenderMode}
            onSetAiRenderMode={setAiRenderMode}
            aiRenderCreativity={aiRenderCreativity}
            onSetAiRenderCreativity={setAiRenderCreativity}
            onAIRenderGenerate={handleAIRenderGenerate}
            isAiRenderLoading={isAiRenderLoading}
            user={user}
            // Floorplan props
            floorplanBaseImageUrl={floorplanBaseImageUrl}
            onFloorplanBaseImageChange={handleFloorplanBaseImageChange}
            onFloorplanGenerate={handleFloorplanGenerate}
            isFloorplanLoading={isFloorplanLoading}
          />

          {activeCategory === 'Moodboard' ? (
            <MoodboardCreator 
              onImageDoubleClick={(url) => { setViewerImageUrl(url); setIsImageViewerOpen(true); }}
            />
          ) : (
            <ImageEditor
              activeCategory={activeCategory}
              onImageDoubleClick={(url) => { setViewerImageUrl(url); setIsImageViewerOpen(true); }}
              selectedStyle={selectedStyle}
              geometryValue={geometryValue}
              selectedFurnitureOption={selectedFurnitureOption}
              buildingState={buildingState}
              furniturePrompt={FURNITURE_OPTIONS.find(o => o.id === selectedFurnitureOption)?.prompt || ''}
              editMode={editMode}
              onSetEditMode={setEditMode}
              onReset={resetEditorState}
              styleSubCategory={styleSubCategory}
              isMoodboard={false}
              contrastValue={contrastValue}
              onSetContrastValue={setContrastValue}
              styleReferenceImage={styleReferenceImage}
              externalResultUrl={
                activeCategory === 'AI Render' ? aiRenderResultUrl :
                activeCategory === 'Floorplan' ? floorplanResultUrl : null
              }
              externalBaseUrl={
                activeCategory === 'AI Render' ? aiRenderBaseImageUrl :
                activeCategory === 'Floorplan' ? floorplanBaseImageUrl : null
              }
              externalLoading={
                activeCategory === 'AI Render' ? isAiRenderLoading :
                activeCategory === 'Floorplan' ? isFloorplanLoading : false
              }
              externalError={
                activeCategory === 'AI Render' ? aiRenderError :
                activeCategory === 'Floorplan' ? floorplanError : null
              }
            />
          )}
      </div>

      <ImageViewerModal
        isOpen={isImageViewerOpen}
        onClose={() => setIsImageViewerOpen(false)}
        imageUrl={viewerImageUrl}
      />
    </div>
  );
}

export default App;

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { generateImage } from '../services/geminiService';
import { UploadIcon, SparklesIcon, ResetIcon, DownloadIcon, CompareIcon, ExpandIcon, CloseIcon } from './icons';
import { EditMode, FurnitureOptionId, Style, Category, BuildingState, StyleSubCategory } from '../types';
import 'image-comparison-slider';

// Fix for custom element 'image-comparison-slider' not being recognized by TypeScript JSX.
const ImageComparisonSlider = 'image-comparison-slider' as any;

interface ImageEditorProps {
  activeCategory: Category['id'];
  onImageDoubleClick: (url: string) => void;
  selectedStyle: Style | null;
  geometryValue: number;
  selectedFurnitureOption: FurnitureOptionId;
  furniturePrompt: string;
  buildingState: BuildingState;
  editMode: EditMode;
  onSetEditMode?: (mode: EditMode) => void;
  onReset?: () => void;
  styleSubCategory?: StyleSubCategory;
  isMoodboard: boolean;
  contrastValue: number;
  onSetContrastValue: (value: number) => void;
  styleReferenceImage: File | null;
  // External props for AI Render mode
  externalResultUrl?: string | null;
  externalBaseUrl?: string | null;
  externalLoading?: boolean;
  externalError?: string | null;
}

export const ImageEditor: React.FC<ImageEditorProps> = ({
  activeCategory,
  onImageDoubleClick,
  selectedStyle,
  geometryValue,
  selectedFurnitureOption,
  furniturePrompt,
  buildingState,
  editMode,
  onSetEditMode,
  onReset,
  styleSubCategory,
  isMoodboard,
  contrastValue,
  onSetContrastValue,
  styleReferenceImage,
  externalResultUrl,
  externalBaseUrl,
  externalLoading,
  externalError,
}) => {
  const [originalImage, setOriginalImage] = useState<File | null>(null);
  const [originalImageUrl, setOriginalImageUrl] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isComparing, setIsComparing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Synchronize with external state (e.g., from AI Render mode)
  useEffect(() => {
    if (externalResultUrl) {
        setGeneratedImageUrl(externalResultUrl);
    }
  }, [externalResultUrl]);

  useEffect(() => {
    if (externalBaseUrl) {
        setOriginalImageUrl(externalBaseUrl);
    }
  }, [externalBaseUrl]);

  useEffect(() => {
    if (externalLoading !== undefined) {
        setIsLoading(externalLoading);
    }
  }, [externalLoading]);

  useEffect(() => {
    if (externalError !== undefined) {
        setError(externalError);
    }
  }, [externalError]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleLocalImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleLocalImageReset = () => {
    setOriginalImage(null);
    setOriginalImageUrl(null);
    setGeneratedImageUrl(null);
    setError(null);
    setIsComparing(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  }

  const handleFullReset = () => {
      // Clear local state
      handleLocalImageReset();
      setPrompt('');
      // Call parent reset if available
      if (onReset) onReset();
  }

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      handleLocalImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleGenerate = useCallback(async () => {
    if (!originalImage) return;

    setIsLoading(true);
    setError(null);
    setGeneratedImageUrl(null);
    setIsComparing(false);

    let finalPrompt = '';
    const userInstruction = prompt.trim() ? ` Additional instructions: ${prompt}` : '';

    // Construction state instruction
    let buildingInstruction = '';
    if (buildingState === 'raw') {
      buildingInstruction = "The input image shows a raw construction state (unfinished concrete/brick shell, no paint, no tiles, no cladding, empty/unfinished pools). COMPLETELY FINISH the building: apply high-quality paints, cladding, flooring, and tiles to all surfaces. If a pool structure is present, tile it and fill it with water. Install windows/doors if missing, and landscape the surroundings. Transform this raw shell into a fully finished property. ";
    }

    if (editMode === 'prompt') {
      if (!prompt && !styleReferenceImage) {
          setError('Please enter a prompt or upload a style reference image.');
          setIsLoading(false);
          return;
      }
      finalPrompt = prompt;
    } else if (editMode === 'styles' && styleSubCategory === 'moodboard') {
        if (!styleReferenceImage) {
            setError('Please upload a moodboard image for reference.');
            setIsLoading(false);
            return;
        }

        // Note: furniturePrompt is intentionally excluded here to avoid conflicting with the strict moodboard instructions
        // which define their own furniture rules (maintain position, change materials).
        finalPrompt = `
          ${buildingInstruction}

          Use the uploaded base interior or exterior image as the primary reference and the uploaded moodboard image as the strict material and style guide.

          Replace all existing materials, textures, and color palettes in the base image with those shown in the moodboard, including:
          – wall finishes and colors
          – floor materials
          – ceiling materials and details
          – furniture materials and finishes
          – pool finishes and tiles (if present)

          Geometry preservation (critical):
          Keep the architecture, proportions, volumes, structure, openings, and camera angle exactly the same as the original image.
          Do not modify walls, floors, ceilings, roofs, openings, pool shape, or spatial layout.

          Furniture & accessories:
          – Maintain existing furniture positions and scale.
          – Change only materials, upholstery, finishes, and colors to match the moodboard.
          – Accessories (curtains, cushions, decor objects, small loose furniture) may be adjusted, replaced, or simplified only if necessary to align with the moodboard style.
          – Do not overcrowd the scene and do not introduce new dominant elements.

          Moodboard adherence (strict):
          – Use the moodboard as the sole reference for textures, materials, colors, and overall design language.
          – Match surface finishes, gloss/matte levels, wood grain direction, stone veining, fabric texture, and pool tile patterns accurately.
          – Do not invent styles, colors, or materials not present in the moodboard.

          Lighting & realism:
          – Create a high-end, editorial-quality architectural image.
          – Use soft, realistic lighting with natural shadows and balanced contrast.
          – Maintain a refined, luxury atmosphere suitable for an architectural presentation or client pitch.
          – Improve material realism, reflections, depth, and texture fidelity without altering the design.

          Output quality:
          – Ultra-realistic, professional architectural visualization
          – Clean, elegant, and presentation-ready
          – No artistic distortion, no stylization, no geometry changes
          – The final image must clearly read as the original project re-materialized according to the moodboard, at a premium architectural standard.

          ${userInstruction}
        `;
    } else if (selectedStyle) {
      finalPrompt = `${buildingInstruction}${furniturePrompt}in a ${selectedStyle.name} style, ${selectedStyle.prompt}${userInstruction}`;
    } else {
        // Fallback or error if no style selected
        if(userInstruction) {
             finalPrompt = `${buildingInstruction}${furniturePrompt}${userInstruction}`;
        } else {
            setError('Please select a style, upload a moodboard, or enter a prompt.');
            setIsLoading(false);
            return;
        }
    }

    try {
      const base64String = await generateImage(originalImage, finalPrompt, geometryValue, contrastValue, styleReferenceImage);
      setGeneratedImageUrl(`data:image/png;base64,${base64String}`);
    } catch (e: any) {
      console.error(e);
      let errorMsg = e.message || 'An error occurred during image generation.';
      if (errorMsg.includes('429') || errorMsg.includes('quota') || errorMsg.includes('RESOURCE_EXHAUSTED')) {
        errorMsg = 'API Quota Exceeded. Please try again later or check your API plan.';
      } else if (errorMsg.includes('503')) {
        errorMsg = 'Service is temporarily unavailable. Please try again shortly.';
      }
      setError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  }, [originalImage, editMode, prompt, selectedStyle, furniturePrompt, geometryValue, contrastValue, styleReferenceImage, buildingState, styleSubCategory]);

  const handleDownload = () => {
    const url = generatedImageUrl || externalResultUrl;
    if (!url) return;
    const link = document.createElement('a');
    link.href = url;
    link.download = `render-master-ai-${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const renderImageContainer = (isOutput: boolean) => {
    const imageUrl = isOutput ? (generatedImageUrl || externalResultUrl) : (originalImageUrl || externalBaseUrl);
    const title = isOutput ? "Generated Image" : "Original Image";

    if (isLoading && isOutput) {
        return (
            <div className="w-full h-full flex flex-col items-center justify-center bg-gray-100 rounded-lg shimmer-bg">
