  onReset?: () => void;
  styleSubCategory?: StyleSubCategory;
  isMoodboard: boolean;
  contrastValue: number;
  onSetContrastValue: (value: number) => void;
  styleReferenceImage: File | null;
  // External props for AI Render mode
  externalResultUrl?: string | null;
  externalBaseUrl?: string | null;
  externalLoading?: boolean;
  externalError?: string | null;
}

export const ImageEditor: React.FC<ImageEditorProps> = ({
  activeCategory,
  onImageDoubleClick,
  selectedStyle,
  geometryValue,
  selectedFurnitureOption,
  furniturePrompt,
  buildingState,
  editMode,
  onSetEditMode,
  onReset,
  styleSubCategory,
  isMoodboard,
  contrastValue,
  onSetContrastValue,
  styleReferenceImage,
  externalResultUrl,
  externalBaseUrl,
  externalLoading,
  externalError,
}) => {
  const [originalImage, setOriginalImage] = useState<File | null>(null);
  const [originalImageUrl, setOriginalImageUrl] = useState<string | null>(null);
  const [generatedImageUrl, setGeneratedImageUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isComparing, setIsComparing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const promptInputRef = useRef<HTMLTextAreaElement>(null);

  // Focus prompt input when switching to prompt mode
  useEffect(() => {
    if (editMode === 'prompt' && promptInputRef.current) {
        promptInputRef.current.focus();
    }
  }, [editMode]);

  // Synchronize with external state (e.g., from AI Render mode)
  useEffect(() => {
    if (externalResultUrl) {
        setGeneratedImageUrl(externalResultUrl);
    }
  }, [externalResultUrl]);

  useEffect(() => {
    if (externalBaseUrl) {
        setOriginalImageUrl(externalBaseUrl);
    }
  }, [externalBaseUrl]);

  useEffect(() => {
    if (externalLoading !== undefined) {
        setIsLoading(externalLoading);
    }
  }, [externalLoading]);

  useEffect(() => {
    if (externalError !== undefined) {
        setError(externalError);
    }
  }, [externalError]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleLocalImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
    }
  };

  const handleLocalImageReset = () => {
    setOriginalImage(null);
    setOriginalImageUrl(null);
    setGeneratedImageUrl(null);
    setError(null);
    setIsComparing(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  }

  const handleFullReset = () => {
      // Clear local state
      handleLocalImageReset();
      setPrompt('');
      // Call parent reset if available
      if (onReset) onReset();
  }

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      handleLocalImageReset();
      setOriginalImage(file);
      setOriginalImageUrl(URL.createObjectURL(file));
